import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Product {
  id: number;
  name: string;
  image: string;
  basePrice: number;
  badge?: string;
}

export interface CartItem {
  id: string; // unique instance id
  productId: number;
  name: string;
  size: string;
  sizeMultiplier: number;
  material: string;
  materialMultiplier: number;
  quantity: number;
  price: number;
}

export interface SizeOption {
  label: string;
  multiplier: number;
}

export interface MaterialOption {
  label: string;
  multiplier: number;
}

import { Product, SizeOption, MaterialOption } from './types';

export const PRODUCTS: Product[] = [
  { id: 1, name: 'Katana High-Poly', image: 'https://picsum.photos/seed/katana/800/600', basePrice: 70000, badge: 'HOT' },
  { id: 2, name: 'Cyberpunk Blaster', image: 'https://picsum.photos/seed/gun/800/600', basePrice: 90000, badge: 'NEW' },
  { id: 3, name: 'Ethereal Figure', image: 'https://picsum.photos/seed/figure/800/600', basePrice: 120000, badge: 'PREMIUM' },
  { id: 4, name: 'Formula 1 Chassis', image: 'https://picsum.photos/seed/f1/800/600', basePrice: 150000, badge: 'LIMIT' },
  { id: 5, name: 'BMW M4 Competition', image: 'https://picsum.photos/seed/bmw/800/600', basePrice: 70000, badge: 'DETAILED' },
  { id: 6, name: 'Raichu Evolution', image: 'https://picsum.photos/seed/raichu/800/600', basePrice: 70000, badge: 'FAVORITE' },
];

export const SIZES: SizeOption[] = [
  { label: '30 cm', multiplier: 1 },
  { label: '50 cm', multiplier: 1.5 },
  { label: '80 cm', multiplier: 2 },
];

export const MATERIALS: MaterialOption[] = [
  { label: 'PLA (Tough)', multiplier: 1 },
  { label: 'Resin (Hyper-Detail)', multiplier: 1.4 },
];

export const CONTACTS = {
  zalo: '0396043085',
  email: 'shopin3d@gmail.com',
  facebook: 'https://www.facebook.com/profile.php?id=61578654816696'
};

import React, { useState, useMemo } from 'react';
import { Product, CartItem } from '../types';
import { SIZES, MATERIALS } from '../constants';
import { ShoppingCart, Check } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  onAddToCart: (item: CartItem) => void;
}

export const ProductCard: React.FC<ProductCardProps> = ({ product, onAddToCart }) => {
  const [sizeIdx, setSizeIdx] = useState(0);
  const [materialIdx, setMaterialIdx] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [isAdding, setIsAdding] = useState(false);

  const currentPrice = useMemo(() => {
    return Math.round(
      product.basePrice * 
      SIZES[sizeIdx].multiplier * 
      MATERIALS[materialIdx].multiplier * 
      quantity
    );
  }, [product.basePrice, sizeIdx, materialIdx, quantity]);

  const handleAdd = () => {
    setIsAdding(true);
    onAddToCart({
      id: `${product.id}-${Date.now()}`,
      productId: product.id,
      name: product.name,
      size: SIZES[sizeIdx].label,
      sizeMultiplier: SIZES[sizeIdx].multiplier,
      material: MATERIALS[materialIdx].label,
      materialMultiplier: MATERIALS[materialIdx].multiplier,
      quantity,
      price: currentPrice
    });
    setTimeout(() => setIsAdding(false), 1500);
  };

  return (
    <div className="group relative glass rounded-2xl overflow-hidden transition-all duration-500 hover:-translate-y-2 hover:shadow-[0_20px_50px_rgba(34,197,94,0.15)]">
      {product.badge && (
        <div className="absolute top-4 left-4 z-10 px-3 py-1 bg-green-500 text-black text-[10px] font-bold tracking-widest rounded-full uppercase">
          {product.badge}
        </div>
      )}

      <div className="relative aspect-[4/3] overflow-hidden">
        <img 
          src={product.image} 
          alt={product.name}
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
      </div>

      <div className="p-6">
        <h3 className="text-xl font-semibold mb-4 text-neutral-100">{product.name}</h3>

        <div className="space-y-4">
          <div>
            <label className="block text-[10px] font-bold text-neutral-500 uppercase tracking-wider mb-2">Kích thước</label>
            <div className="flex gap-2">
              {SIZES.map((s, idx) => (
                <button
                  key={s.label}
                  onClick={() => setSizeIdx(idx)}
                  className={`flex-1 py-2 text-xs rounded-lg transition-all border ${
                    sizeIdx === idx 
                      ? 'bg-green-500/10 border-green-500 text-green-500' 
                      : 'border-neutral-800 text-neutral-400 hover:border-neutral-600'
                  }`}
                >
                  {s.label}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-bold text-neutral-500 uppercase tracking-wider mb-2">Vật liệu</label>
            <div className="flex gap-2">
              {MATERIALS.map((m, idx) => (
                <button
                  key={m.label}
                  onClick={() => setMaterialIdx(idx)}
                  className={`flex-1 py-2 text-xs rounded-lg transition-all border ${
                    materialIdx === idx 
                      ? 'bg-green-500/10 border-green-500 text-green-500' 
                      : 'border-neutral-800 text-neutral-400 hover:border-neutral-600'
                  }`}
                >
                  {m.label.split(' ')[0]}
                </button>
              ))}
            </div>
          </div>

          <div className="flex items-end justify-between pt-4">
            <div>
              <label className="block text-[10px] font-bold text-neutral-500 uppercase tracking-wider mb-1">Số lượng</label>
              <input 
                type="number" 
                value={quantity}
                onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
                className="w-16 bg-neutral-900 border border-neutral-800 rounded-lg px-2 py-1 text-sm focus:outline-none focus:border-green-500"
              />
            </div>
            <div className="text-right">
              <span className="block text-[10px] text-neutral-500 uppercase font-bold tracking-widest">Giá tạm tính</span>
              <span className="text-2xl font-bold text-green-500">{currentPrice.toLocaleString()}đ</span>
            </div>
          </div>

          <button
            onClick={handleAdd}
            disabled={isAdding}
            className={`w-full py-4 rounded-xl flex items-center justify-center gap-2 font-bold transition-all ${
              isAdding 
                ? 'bg-neutral-800 text-green-500' 
                : 'bg-green-500 hover:bg-green-400 text-black active:scale-[0.98]'
            }`}
          >
            {isAdding ? (
              <>
                <Check size={20} />
                Đã thêm
              </>
            ) : (
              <>
                <ShoppingCart size={20} />
                Thêm vào giỏ
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Trophy, X } from 'lucide-react';

interface LuckySpinProps {
  onWin: (discount: number) => void;
  onClose: () => void;
}

export const LuckySpin: React.FC<LuckySpinProps> = ({ onWin, onClose }) => {
  const [isSpinning, setIsSpinning] = useState(false);
  const [result, setResult] = useState<number | null>(null);
  const slotRef = useRef<HTMLDivElement>(null);

  const rewards = [0, 5, 10, 15, 20];
  const items = [...rewards, ...rewards, ...rewards]; // Repeat for visual effect

  const handleSpin = () => {
    if (isSpinning) return;
    setIsSpinning(true);
    setResult(null);

    const winningIdx = Math.floor(Math.random() * rewards.length);
    const winValue = rewards[winningIdx];

    // Calculate final position
    const itemHeight = 80;
    const finalIdx = (items.length - rewards.length) + winningIdx;
    const offset = finalIdx * itemHeight;

    if (slotRef.current) {
      slotRef.current.style.transition = 'none';
      slotRef.current.style.transform = 'translateY(0)';
      // Trigger reflow
      slotRef.current.offsetHeight;

      slotRef.current.style.transition = 'transform 3s cubic-bezier(0.1, 0.7, 0.1, 1)';
      slotRef.current.style.transform = `translateY(-${offset}px)`;
    }

    setTimeout(() => {
      setIsSpinning(false);
      setResult(winValue);
      onWin(winValue);
    }, 3200);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
      <div className="relative glass w-full max-w-md p-8 rounded-3xl text-center overflow-hidden">
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 text-neutral-500 hover:text-neutral-100 transition-colors"
        >
          <X size={24} />
        </button>

        <div className="inline-flex items-center justify-center w-16 h-16 bg-green-500/10 rounded-2xl mb-6 text-green-500">
          <Trophy size={32} />
        </div>

        <h2 className="text-3xl font-bold mb-2">Vòng quay May mắn</h2>
        <p className="text-neutral-400 mb-8">Nhận ưu đãi lên đến 20% cho đơn hàng tiếp theo</p>

        <div className="relative mb-8">
          <div className="w-32 h-20 mx-auto border-2 border-green-500/30 rounded-2xl overflow-hidden bg-neutral-900 shadow-inner">
            <div ref={slotRef} className="flex flex-col">
              {items.map((val, i) => (
                <div key={i} className="h-20 flex items-center justify-center text-4xl font-black text-green-500">
                  {val}%
                </div>
              ))}
            </div>
          </div>
          <div className="absolute left-1/2 -translate-x-1/2 top-1/2 -translate-y-1/2 w-40 h-10 border-y border-green-500 pointer-events-none opacity-20" />
        </div>

        <button
          onClick={handleSpin}
          disabled={isSpinning || result !== null}
          className={`w-full py-4 rounded-xl font-bold text-lg transition-all ${
            isSpinning || result !== null
              ? 'bg-neutral-800 text-neutral-500 cursor-not-allowed'
              : 'bg-green-500 hover:bg-green-400 text-black shadow-[0_10px_30px_rgba(34,197,94,0.3)]'
          }`}
        >
          {isSpinning ? 'Đang quay...' : result !== null ? 'Hoàn thành' : 'Quay ngay'}
        </button>

        {result !== null && (
          <div className="mt-6 animate-bounce">
            {result > 0 ? (
              <p className="text-green-400 font-bold">🎉 Tuyệt vời! Bạn nhận được Voucher -{result}%</p>
            ) : (
              <p className="text-neutral-500">May mắn hơn vào lần sau nhé! 🍀</p>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ShoppingBag, MessageSquare, Mail, Facebook, Send, Trash2, Gift, Sparkles } from 'lucide-react';
import { ProductCard } from './components/ProductCard';
import { LuckySpin } from './components/LuckySpin';
import { PRODUCTS, CONTACTS } from './constants';
import { CartItem } from './types';

const App: React.FC = () => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [discount, setDiscount] = useState(0);
  const [showLucky, setShowLucky] = useState(false);
  const [hasSpun, setHasSpun] = useState(false);
  const [isCartOpen, setIsCartOpen] = useState(false);

  const subtotal = cart.reduce((acc, item) => acc + item.price, 0);
  const total = subtotal * (1 - discount / 100);

  const addToCart = (item: CartItem) => {
    setCart(prev => [...prev, item]);
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const handleOrder = () => {
    if (cart.length === 0) return alert('Giỏ hàng trống!');

    let message = "📦 ĐƠN HÀNG MỚI - SHOP IN 3D\n\n";
    cart.forEach(item => {
      message += `• ${item.name} (${item.size}, ${item.material}) x${item.quantity}: ${item.price.toLocaleString()}đ\n`;
    });

    if (discount > 0) message += `\n🎁 Voucher giảm: ${discount}%`;
    message += `\n💰 TỔNG CỘNG: ${total.toLocaleString()}đ`;

    const url = `https://zalo.me/${CONTACTS.zalo}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Navigation */}
      <nav className="sticky top-0 z-40 glass border-b border-white/5 px-6 py-4">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-green-500 flex items-center justify-center text-black font-black italic shadow-lg">3D</div>
            <h1 className="text-xl font-bold tracking-tight">SHOP IN <span className="text-green-500">3D</span></h1>
          </div>

          <div className="flex items-center gap-6">
            <button 
              onClick={() => !hasSpun && setShowLucky(true)}
              className={`hidden sm:flex items-center gap-2 px-4 py-2 rounded-full text-sm font-semibold transition-all ${
                hasSpun ? 'text-neutral-500 cursor-not-allowed' : 'bg-green-500/10 text-green-500 hover:bg-green-500/20'
              }`}
            >
              <Gift size={18} />
              {hasSpun ? 'Đã quay thưởng' : 'Nhận quà'}
            </button>
            <button 
              onClick={() => setIsCartOpen(!isCartOpen)}
              className="relative p-2 text-neutral-300 hover:text-white transition-colors"
            >
              <ShoppingBag size={24} />
              {cart.length > 0 && (
                <span className="absolute -top-1 -right-1 w-5 h-5 bg-green-500 text-black text-[10px] font-bold rounded-full flex items-center justify-center">
                  {cart.length}
                </span>
              )}
            </button>
          </div>
        </div>
      </nav>

      {/* Hero */}
      <section className="relative pt-20 pb-16 px-6 overflow-hidden">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[800px] h-[400px] bg-green-500/10 blur-[120px] rounded-full pointer-events-none" />
        <div className="max-w-7xl mx-auto text-center relative z-10">
          <div className="inline-flex items-center gap-2 px-4 py-1 rounded-full bg-neutral-900 border border-neutral-800 text-[10px] uppercase font-bold tracking-[0.2em] text-neutral-400 mb-6">
            <Sparkles size={14} className="text-green-500" />
            Xưởng in 3D Chuyên Nghiệp
          </div>
          <h2 className="text-5xl md:text-7xl font-black mb-6 tracking-tight leading-tight">
            Hiện thực hóa mọi <br /> 
            <span className="gradient-text">ý tưởng sáng tạo</span>
          </h2>
          <p className="max-w-2xl mx-auto text-neutral-400 text-lg leading-relaxed">
            Công nghệ in 3D FDM & Resin tiên tiến, mang lại độ sắc nét tuyệt đối cho từng mô hình figure, trang trí và công nghiệp.
          </p>
        </div>
      </section>

      {/* Main Grid */}
      <main className="flex-1 max-w-7xl mx-auto px-6 pb-24 w-full">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {PRODUCTS.map(product => (
            <ProductCard 
              key={product.id} 
              product={product} 
              onAddToCart={addToCart} 
            />
          ))}
        </div>
      </main>

      {/* Footer */}
      <footer className="glass border-t border-white/5 py-16 px-6">
        <div className="max-w-7xl mx-auto">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-12 mb-12">
            <div>
              <h3 className="text-xl font-bold mb-6">Về chúng tôi</h3>
              <p className="text-neutral-400 leading-relaxed text-sm">
                Shop in 3D cung cấp dịch vụ in ấn theo yêu cầu với vật liệu cao cấp. Đội ngũ kỹ thuật hỗ trợ tối ưu hóa thiết kế trước khi in.
              </p>
            </div>
            <div>
              <h3 className="text-xl font-bold mb-6">Kết nối</h3>
              <div className="flex flex-col gap-4">
                <a href={`https://zalo.me/${CONTACTS.zalo}`} target="_blank" className="flex items-center gap-3 text-neutral-400 hover:text-green-500 transition-colors">
                  <div className="w-8 h-8 rounded-lg bg-neutral-900 flex items-center justify-center border border-neutral-800"><MessageSquare size={16}/></div>
                  <span>Zalo: {CONTACTS.zalo}</span>
                </a>
                <a href={CONTACTS.facebook} target="_blank" className="flex items-center gap-3 text-neutral-400 hover:text-green-500 transition-colors">
                  <div className="w-8 h-8 rounded-lg bg-neutral-900 flex items-center justify-center border border-neutral-800"><Facebook size={16}/></div>
                  <span>Facebook Studio</span>
                </a>
                <a href={`mailto:${CONTACTS.email}`} className="flex items-center gap-3 text-neutral-400 hover:text-green-500 transition-colors">
                  <div className="w-8 h-8 rounded-lg bg-neutral-900 flex items-center justify-center border border-neutral-800"><Mail size={16}/></div>
                  <span>{CONTACTS.email}</span>
                </a>
              </div>
            </div>
            <div>
              <h3 className="text-xl font-bold mb-6">Cập nhật tin tức</h3>
              <div className="flex gap-2">
                <input type="text" placeholder="Email của bạn" className="flex-1 bg-neutral-900 border border-neutral-800 rounded-xl px-4 text-sm focus:outline-none focus:border-green-500"/>
                <button className="p-3 bg-green-500 rounded-xl text-black"><Send size={18}/></button>
              </div>
            </div>
          </div>
          <div className="text-center pt-8 border-t border-white/5 text-neutral-600 text-[10px] uppercase font-bold tracking-widest">
            © 2024 SHOP IN 3D STUDIO. ALL RIGHTS RESERVED.
          </div>
        </div>
      </footer>

      {/* Cart Drawer Overlay */}
      {isCartOpen && (
        <div className="fixed inset-0 z-50 flex justify-end">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)} />
          <div className="relative w-full max-w-md glass h-full border-l border-white/10 shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
            <div className="p-6 border-b border-white/10 flex items-center justify-between">
              <h2 className="text-2xl font-bold flex items-center gap-3">
                <ShoppingBag className="text-green-500" />
                Giỏ hàng
              </h2>
              <button onClick={() => setIsCartOpen(false)} className="p-2 hover:bg-neutral-800 rounded-full transition-colors">
                <X size={20} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-6">
              {cart.length === 0 ? (
                <div className="text-center py-20 opacity-40">
                  <ShoppingBag size={64} className="mx-auto mb-4" />
                  <p>Giỏ hàng đang trống</p>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.id} className="group glass p-4 rounded-xl border-white/5 relative">
                    <button 
                      onClick={() => removeFromCart(item.id)}
                      className="absolute top-2 right-2 p-1.5 opacity-0 group-hover:opacity-100 text-red-500 hover:bg-red-500/10 rounded-lg transition-all"
                    >
                      <Trash2 size={16} />
                    </button>
                    <div className="flex flex-col gap-1">
                      <h4 className="font-bold text-neutral-100">{item.name}</h4>
                      <div className="flex items-center gap-2 text-[10px] text-neutral-500 uppercase font-bold">
                        <span>{item.size}</span>
                        <span className="w-1 h-1 bg-neutral-700 rounded-full" />
                        <span>{item.material}</span>
                        <span className="w-1 h-1 bg-neutral-700 rounded-full" />
                        <span>SL: {item.quantity}</span>
                      </div>
                      <div className="text-lg font-black text-green-500 mt-2">{item.price.toLocaleString()}đ</div>
                    </div>
                  </div>
                ))
              )}
            </div>

            <div className="p-6 border-t border-white/10 glass">
              <div className="space-y-2 mb-6 text-sm">
                <div className="flex justify-between text-neutral-400">
                  <span>Tạm tính:</span>
                  <span>{subtotal.toLocaleString()}đ</span>
                </div>
                {discount > 0 && (
                  <div className="flex justify-between text-green-500">
                    <span>Ưu đãi (Voucher {discount}%):</span>
                    <span>-{ (subtotal * discount / 100).toLocaleString() }đ</span>
                  </div>
                )}
                <div className="flex justify-between text-xl font-black pt-2 border-t border-white/5">
                  <span>TỔNG CỘNG:</span>
                  <span className="text-green-500">{total.toLocaleString()}đ</span>
                </div>
              </div>

              <button 
                onClick={handleOrder}
                className="w-full py-4 bg-green-500 text-black font-black rounded-xl hover:bg-green-400 transition-all flex items-center justify-center gap-2 shadow-[0_10px_40px_rgba(34,197,94,0.2)]"
              >
                <MessageSquare size={20}/>
                ĐẶT HÀNG QUA ZALO
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Lucky Spin Modal */}
      {showLucky && (
        <LuckySpin 
          onWin={(val) => {
            setDiscount(val);
            setHasSpun(true);
          }} 
          onClose={() => setShowLucky(false)} 
        />
      )}

      {/* Lucky Trigger Button (Sticky) */}
      {!hasSpun && !showLucky && (
        <button 
          onClick={() => setShowLucky(true)}
          className="fixed bottom-8 right-8 z-40 w-16 h-16 bg-green-500 rounded-full flex items-center justify-center text-black shadow-[0_10px_50px_rgba(34,197,94,0.4)] hover:scale-110 active:scale-95 transition-all group"
        >
          <Gift size={28} className="group-hover:rotate-12 transition-transform" />
          <span className="absolute -top-12 right-0 bg-neutral-900 border border-neutral-800 text-[10px] font-bold py-1 px-3 rounded-lg text-neutral-300 opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
            Quay số nhận thưởng
          </span>
        </button>
      )}
    </div>
  );
};

export default App;

// Helper icons
