  name: string;
  size: string;
  sizeMultiplier: number;
  material: string;
  materialMultiplier: number;
  quantity: number;
  price: number;
}

export interface SizeOption {
  label: string;
  multiplier: number;
}

export interface MaterialOption {
  label: string;
  multiplier: number;
}

import React, { useState, useMemo } from 'react';
import { Product, CartItem } from '../types';
import { SIZES, MATERIALS } from '../constants';
import { ShoppingCart, Check, Heart } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  isWishlisted: boolean;
  onAddToCart: (item: CartItem) => void;
  onToggleWishlist: (product: Product) => void;
}

export const ProductCard: React.FC<ProductCardProps> = ({ 
  product, 
  isWishlisted, 
  onAddToCart, 
  onToggleWishlist 
}) => {
  const [sizeIdx, setSizeIdx] = useState(0);
  const [materialIdx, setMaterialIdx] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [isAdding, setIsAdding] = useState(false);

  const currentPrice = useMemo(() => {
    return Math.round(
      product.basePrice * 
      SIZES[sizeIdx].multiplier * 
      MATERIALS[materialIdx].multiplier * 
      quantity
    );
  }, [product.basePrice, sizeIdx, materialIdx, quantity]);

  const handleAdd = () => {
    setIsAdding(true);
    onAddToCart({
      id: `${product.id}-${Date.now()}`,
      productId: product.id,
      name: product.name,
      size: SIZES[sizeIdx].label,
      sizeMultiplier: SIZES[sizeIdx].multiplier,
      material: MATERIALS[materialIdx].label,
      materialMultiplier: MATERIALS[materialIdx].multiplier,
      quantity,
      price: currentPrice
    });
    setTimeout(() => setIsAdding(false), 1500);
  };

  return (
    <div className="group relative glass rounded-2xl overflow-hidden transition-all duration-500 hover:-translate-y-2 hover:shadow-[0_20px_50px_rgba(34,197,94,0.15)]">
      {product.badge && (
        <div className="absolute top-4 left-4 z-10 px-3 py-1 bg-green-500 text-black text-[10px] font-bold tracking-widest rounded-full uppercase">
          {product.badge}
        </div>
      )}

      <button 
        onClick={() => onToggleWishlist(product)}
        className={`absolute top-4 right-4 z-10 p-2 rounded-full glass transition-all duration-300 ${
          isWishlisted ? 'text-red-500 bg-red-500/10 border-red-500/50' : 'text-neutral-400 hover:text-white'
        }`}
      >
        <Heart size={18} fill={isWishlisted ? "currentColor" : "none"} />
      </button>

      <div className="relative aspect-[4/3] overflow-hidden">
        <img 
          src={product.image} 
          alt={product.name}
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
      </div>

      <div className="p-6">
        <h3 className="text-xl font-semibold mb-4 text-neutral-100">{product.name}</h3>

        <div className="space-y-4">
          <div>
            <label className="block text-[10px] font-bold text-neutral-500 uppercase tracking-wider mb-2">Kích thước</label>
            <div className="flex gap-2">
              {SIZES.map((s, idx) => (
                <button
                  key={s.label}
                  onClick={() => setSizeIdx(idx)}
                  className={`flex-1 py-2 text-xs rounded-lg transition-all border ${
                    sizeIdx === idx 
                      ? 'bg-green-500/10 border-green-500 text-green-500' 
                      : 'border-neutral-800 text-neutral-400 hover:border-neutral-600'
                  }`}
                >
                  {s.label}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-bold text-neutral-500 uppercase tracking-wider mb-2">Vật liệu</label>
            <div className="flex gap-2">
              {MATERIALS.map((m, idx) => (
                <button
                  key={m.label}
                  onClick={() => setMaterialIdx(idx)}
                  className={`flex-1 py-2 text-xs rounded-lg transition-all border ${
                    materialIdx === idx 
                      ? 'bg-green-500/10 border-green-500 text-green-500' 
                      : 'border-neutral-800 text-neutral-400 hover:border-neutral-600'
                  }`}
                >
                  {m.label.split(' ')[0]}
                </button>
              ))}
            </div>
          </div>

          <div className="flex items-end justify-between pt-4">
            <div>
              <label className="block text-[10px] font-bold text-neutral-500 uppercase tracking-wider mb-1">Số lượng</label>
              <input 
                type="number" 
                value={quantity}
                onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
                className="w-16 bg-neutral-900 border border-neutral-800 rounded-lg px-2 py-1 text-sm focus:outline-none focus:border-green-500"
              />
            </div>
            <div className="text-right">
              <span className="block text-[10px] text-neutral-500 uppercase font-bold tracking-widest">Giá tạm tính</span>
              <span className="text-2xl font-bold text-green-500">{currentPrice.toLocaleString()}đ</span>
            </div>
          </div>

          <button
            onClick={handleAdd}
            disabled={isAdding}
            className={`w-full py-4 rounded-xl flex items-center justify-center gap-2 font-bold transition-all ${
              isAdding 
                ? 'bg-neutral-800 text-green-500' 
                : 'bg-green-500 hover:bg-green-400 text-black active:scale-[0.98]'
            }`}
          >
            {isAdding ? (
              <>
                <Check size={20} />
                Đã thêm
              </>
            ) : (
              <>
                <ShoppingCart size={20} />
                Thêm vào giỏ
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ShoppingBag, MessageSquare, Mail, Facebook, Send, Trash2, Gift, Sparkles, Heart, X, ChevronRight } from 'lucide-react';
