                          onClick={() => toggleWishlist(product)}
                          className="text-[10px] uppercase font-bold tracking-widest text-red-500/70 hover:text-red-500 transition-colors"
                        >
                          Xóa
                        </button>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>

            <div className="p-6 border-t border-white/10 glass text-center">
              <p className="text-xs text-neutral-500 mb-4">Các mẫu yêu thích sẽ được lưu lại để bạn dễ dàng tìm thấy sau này.</p>
