                onClick={() => setIsWishlistOpen(false)}
                className="w-full py-3 bg-neutral-800 text-white rounded-xl hover:bg-neutral-700 transition-all font-bold"
              >
                Tiếp tục mua sắm
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Lucky Spin Modal */}
      {showLucky && (
        <LuckySpin 
          onWin={(val) => {
            setDiscount(val);
            setHasSpun(true);
          }} 
          onClose={() => setShowLucky(false)} 
        />
      )}

      {/* Lucky Trigger Button (Sticky) */}
      {!hasSpun && !showLucky && (
        <button 
          onClick={() => setShowLucky(true)}
          className="fixed bottom-8 left-8 z-40 w-16 h-16 bg-green-500 rounded-full flex items-center justify-center text-black shadow-[0_10px_50px_rgba(34,197,94,0.4)] hover:scale-110 active:scale-95 transition-all group"
        >
          <Gift size={28} className="group-hover:rotate-12 transition-transform" />
          <span className="absolute -top-12 left-0 bg-neutral-900 border border-neutral-800 text-[10px] font-bold py-1 px-3 rounded-lg text-neutral-300 opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
            Quay số nhận thưởng
          </span>
        </button>
      )}
    </div>
  );
};

