import React, { useState, useRef, useEffect } from 'react';
import { Trophy, X, PartyPopper, Sparkles } from 'lucide-react';

interface LuckySpinProps {
  onWin: (discount: number) => void;
  onClose: () => void;
}

export const LuckySpin: React.FC<LuckySpinProps> = ({ onWin, onClose }) => {
  const [isSpinning, setIsSpinning] = useState(false);
  const [result, setResult] = useState<number | null>(null);
  const slotRef = useRef<HTMLDivElement>(null);

  const rewards = [0, 5, 10, 15, 20];
  const items = [...rewards, ...rewards, ...rewards, ...rewards]; // More items for longer spin

  const handleSpin = () => {
    if (isSpinning) return;
    setIsSpinning(true);
    setResult(null);

    const winningIdx = Math.floor(Math.random() * rewards.length);
    const winValue = rewards[winningIdx];

    const itemHeight = 100;
    const finalIdx = (items.length - rewards.length) + winningIdx;
    const offset = finalIdx * itemHeight;

    if (slotRef.current) {
      slotRef.current.style.transition = 'none';
      slotRef.current.style.transform = 'translateY(0)';
      slotRef.current.offsetHeight;

      slotRef.current.style.transition = 'transform 4s cubic-bezier(0.1, 0.7, 0.1, 1)';
      slotRef.current.style.transform = `translateY(-${offset}px)`;
    }

    setTimeout(() => {
      setIsSpinning(false);
      setResult(winValue);
      onWin(winValue);
    }, 4200);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-900/30 backdrop-blur-sm">
      <div className="relative bg-white w-full max-w-md p-10 rounded-[2.5rem] text-center shadow-2xl overflow-hidden border border-white">
        {/* Confetti Background Elements */}
        <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-sky-400 via-emerald-400 to-amber-400" />

        <button 
          onClick={onClose}
          className="absolute top-6 right-6 p-2 text-slate-300 hover:text-slate-600 hover:bg-slate-50 rounded-full transition-all"
        >
          <X size={24} />
        </button>

        <div className="inline-flex items-center justify-center w-20 h-20 bg-amber-50 rounded-3xl mb-6 text-amber-500 floating">
          <Trophy size={40} />
        </div>

        <h2 className="text-3xl font-extrabold mb-2 text-slate-800">Quay Thưởng May Mắn!</h2>
        <p className="text-slate-500 mb-10 font-medium">Bạn có cơ hội nhận mã giảm giá lên đến 20%</p>

        <div className="relative mb-10">
          <div className="w-40 h-[100px] mx-auto border-4 border-slate-50 rounded-[2rem] overflow-hidden bg-slate-50 shadow-inner relative">
            <div ref={slotRef} className="flex flex-col">
              {items.map((val, i) => (
                <div key={i} className={`h-[100px] flex items-center justify-center text-5xl font-black ${val > 0 ? 'text-emerald-500' : 'text-slate-300'}`}>
                  {val}%
                </div>
              ))}
            </div>
            {/* Indicator Lines */}
            <div className="absolute inset-x-0 top-1/2 -translate-y-1/2 flex items-center justify-between px-2 pointer-events-none">
                <div className="w-1.5 h-6 bg-emerald-500 rounded-full" />
                <div className="w-1.5 h-6 bg-emerald-500 rounded-full" />
            </div>
          </div>

          {/* Sparkles */}
          <div className="absolute -top-4 -right-2 text-amber-400 animate-pulse"><Sparkles size={24}/></div>
          <div className="absolute -bottom-2 -left-4 text-sky-400 animate-bounce"><PartyPopper size={24}/></div>
        </div>

        <button
          onClick={handleSpin}
          disabled={isSpinning || result !== null}
          className={`w-full py-5 rounded-2xl font-black text-lg transition-all transform active:scale-95 ${
            isSpinning || result !== null
              ? 'bg-slate-100 text-slate-400 cursor-not-allowed'
              : 'bg-slate-900 text-white shadow-xl hover:bg-slate-800'
          }`}
        >
          {isSpinning ? 'ĐANG QUAY...' : result !== null ? 'XEM KẾT QUẢ' : 'QUAY NGAY!'}
        </button>

        {result !== null && (
          <div className="mt-8 p-6 bg-emerald-50 rounded-3xl border border-emerald-100 animate-in fade-in zoom-in duration-500">
            {result > 0 ? (
              <>
                <p className="text-emerald-600 font-extrabold text-lg mb-1">🎉 CHÚC MỪNG BẠN!</p>
                <p className="text-emerald-500 font-medium">Bạn đã nhận được mã giảm giá <span className="font-black text-2xl">{result}%</span></p>
              </>
            ) : (
              <>
                <p className="text-slate-600 font-bold mb-1">Ồ! Suýt trúng rồi...</p>
                <p className="text-slate-400 text-sm font-medium">Cảm ơn bạn đã tham gia, hẹn bạn lần sau nhé! 🍀</p>
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

