                <Box size={28} strokeWidth={2.5} />
              </div>
              <div className="flex flex-col">
                <h1 className="text-xl font-extrabold tracking-tight leading-none text-slate-800">
                    SHOPIN<span className="text-sky-500 italic">3D</span>
                </h1>
                <span className="text-[9px] uppercase font-black text-slate-400 tracking-[0.3em]">Creative Hub</span>
              </div>
            </div>
          </div>

          <div className="hidden lg:flex items-center gap-10">
            {['Sản phẩm', 'Về chúng tôi', 'Hướng dẫn', 'Liên hệ'].map(item => (
                <a key={item} href="#" className="text-sm font-bold text-slate-600 hover:text-sky-500 transition-colors uppercase tracking-widest">{item}</a>
            ))}
          </div>

          <div className="flex items-center gap-2 sm:gap-4">
