                onClick={() => setIsWishlistOpen(true)}
                className="relative p-3 text-slate-500 hover:text-rose-500 transition-colors"
                >
                <Heart size={22} className={wishlist.length > 0 ? "fill-rose-500 text-rose-500" : ""} />
                {wishlist.length > 0 && (
