import React, { useState, useMemo } from 'react';
import { Product, CartItem } from '../types';
import { SIZES, MATERIALS } from '../constants';
import { ShoppingCart, Check, Heart } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  isWishlisted: boolean;
  onAddToCart: (item: CartItem) => void;
  onToggleWishlist: (product: Product) => void;
}

export const ProductCard: React.FC<ProductCardProps> = ({ 
  product, 
  isWishlisted, 
  onAddToCart, 
  onToggleWishlist 
}) => {
  const [sizeIdx, setSizeIdx] = useState(0);
  const [materialIdx, setMaterialIdx] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [isAdding, setIsAdding] = useState(false);

  const currentPrice = useMemo(() => {
    return Math.round(
      product.basePrice * 
      SIZES[sizeIdx].multiplier * 
      MATERIALS[materialIdx].multiplier * 
      quantity
    );
  }, [product.basePrice, sizeIdx, materialIdx, quantity]);

  const handleAdd = () => {
    setIsAdding(true);
    onAddToCart({
      id: `${product.id}-${Date.now()}`,
      productId: product.id,
      name: product.name,
      size: SIZES[sizeIdx].label,
      sizeMultiplier: SIZES[sizeIdx].multiplier,
      material: MATERIALS[materialIdx].label,
      materialMultiplier: MATERIALS[materialIdx].multiplier,
      quantity,
      price: currentPrice
    });
    setTimeout(() => setIsAdding(false), 1500);
  };

  return (
    <div className="group relative bg-[#fdfdfd] rounded-[2rem] overflow-hidden transition-all duration-500 card-shadow card-shadow-hover border border-[#f1f1ee]" id={`product-${product.id}`}>
      {/* Action Buttons */}
      <button 
        onClick={() => onToggleWishlist(product)}
        className={`absolute top-5 right-5 z-10 p-2.5 rounded-full bg-white/70 backdrop-blur-md shadow-sm transition-all duration-300 hover:scale-105 active:scale-95 border border-white/50 ${
          isWishlisted ? 'text-rose-400' : 'text-slate-300 hover:text-rose-300'
        }`}
      >
        <Heart size={18} fill={isWishlisted ? "currentColor" : "none"} />
      </button>

      {/* Image Section */}
      <div className="relative aspect-[5/4] bg-[#f9f9f6] overflow-hidden">
        <img 
          src={product.image} 
          alt={product.name}
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
        />
        {product.badge && (
          <div className="absolute top-5 left-5 px-3 py-1 bg-[#88a088]/90 text-white text-[9px] font-bold tracking-widest rounded-lg uppercase backdrop-blur-sm">
            {product.badge}
          </div>
        )}
      </div>

      <div className="p-8">
        <h3 className="text-lg font-bold mb-6 text-slate-700 tracking-tight">
          {product.name}
        </h3>

        <div className="space-y-6">
          {/* Size Select */}
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-[0.15em] mb-3">Kích thước</label>
            <div className="flex gap-2 p-1.5 bg-[#f5f5f2] rounded-2xl border border-[#eeeeea]">
              {SIZES.map((s, idx) => (
                <button
                  key={s.label}
                  onClick={() => setSizeIdx(idx)}
                  className={`flex-1 py-2 text-[11px] font-bold rounded-xl transition-all ${
                    sizeIdx === idx 
                      ? 'bg-white text-slate-700 shadow-sm border border-slate-100' 
                      : 'text-slate-400 hover:text-slate-500'
                  }`}
                >
                  {s.label}
                </button>
              ))}
            </div>
          </div>

          {/* Material Select */}
          <div>
            <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-[0.15em] mb-3">Vật liệu</label>
            <div className="flex gap-2">
              {MATERIALS.map((m, idx) => (
                <button
                  key={m.label}
                  onClick={() => setMaterialIdx(idx)}
                  className={`flex-1 py-2 text-[11px] font-bold rounded-xl border transition-all ${
                    materialIdx === idx 
                      ? 'bg-[#88a088]/10 border-[#88a088]/30 text-[#6b8e8e]' 
                      : 'bg-white border-[#eeeeea] text-slate-300 hover:border-slate-200 hover:text-slate-400'
                  }`}
                >
                  {m.label.split(' ')[0]}
                </button>
              ))}
            </div>
          </div>

          {/* Price & Quantity */}
          <div className="flex items-center justify-between pt-5 border-t border-[#f5f5f2]">
            <div className="flex flex-col">
              <span className="text-xl font-bold text-slate-700">
                {currentPrice.toLocaleString()}đ
              </span>
              <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">Giá hoàn thiện</span>
            </div>
            <div className="flex items-center bg-[#f5f5f2] rounded-xl p-1 gap-1 border border-[#eeeeea]">
                <button 
                    onClick={() => setQuantity(q => Math.max(1, q - 1))}
                    className="w-7 h-7 flex items-center justify-center bg-white rounded-lg text-slate-400 hover:text-slate-600 transition-colors shadow-sm"
                >-</button>
                <span className="w-6 text-center text-xs font-bold text-slate-600">{quantity}</span>
                <button 
                    onClick={() => setQuantity(q => q + 1)}
                    className="w-7 h-7 flex items-center justify-center bg-white rounded-lg text-slate-400 hover:text-slate-600 transition-colors shadow-sm"
                >+</button>
            </div>
          </div>

          <button
            onClick={handleAdd}
            disabled={isAdding}
            className={`w-full py-4 rounded-2xl flex items-center justify-center gap-3 font-bold text-xs tracking-widest transition-all ${
              isAdding 
                ? 'bg-[#88a088] text-white' 
                : 'bg-slate-800 text-white hover:bg-slate-700 shadow-lg shadow-slate-900/5 active:scale-[0.98]'
            }`}
          >
            {isAdding ? (
              <>
                <Check size={18} />
                ĐÃ THÊM VÀO GIỎ
              </>
            ) : (
              <>
                <ShoppingCart size={18} />
                MUA SẢN PHẨM
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ShoppingBag, MessageSquare, Mail, Facebook, Send, Trash2, Gift, Sparkles, Heart, X, ChevronRight, Menu, Zap, ShieldCheck, Truck, Box } from 'lucide-react';
import { ProductCard } from './components/ProductCard';
import { LuckySpin } from './components/LuckySpin';
import { PRODUCTS, CONTACTS } from './constants';
import { CartItem, Product } from './types';

const App: React.FC = () => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [wishlist, setWishlist] = useState<Product[]>([]);
  const [discount, setDiscount] = useState(0);
  const [showLucky, setShowLucky] = useState(false);
  const [hasSpun, setHasSpun] = useState(false);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isWishlistOpen, setIsWishlistOpen] = useState(false);

  useEffect(() => {
    const savedWishlist = localStorage.getItem('wishlist');
    if (savedWishlist) setWishlist(JSON.parse(savedWishlist));

    const savedCart = localStorage.getItem('cart');
    if (savedCart) setCart(JSON.parse(savedCart));

    const savedHasSpun = localStorage.getItem('hasSpun');
    if (savedHasSpun) setHasSpun(JSON.parse(savedHasSpun));

    const savedDiscount = localStorage.getItem('discount');
    if (savedDiscount) setDiscount(JSON.parse(savedDiscount));
  }, []);

  useEffect(() => {
    localStorage.setItem('wishlist', JSON.stringify(wishlist));
  }, [wishlist]);

  useEffect(() => {
    localStorage.setItem('cart', JSON.stringify(cart));
    localStorage.setItem('hasSpun', JSON.stringify(hasSpun));
    localStorage.setItem('discount', JSON.stringify(discount));
  }, [cart, hasSpun, discount]);

  const subtotal = cart.reduce((acc, item) => acc + item.price, 0);
  const total = subtotal * (1 - discount / 100);

  const addToCart = (item: CartItem) => {
    setCart(prev => [...prev, item]);
    setIsCartOpen(true);
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const toggleWishlist = (product: Product) => {
    setWishlist(prev => {
      const exists = prev.find(p => p.id === product.id);
      if (exists) return prev.filter(p => p.id !== product.id);
      return [...prev, product];
    });
  };

  const handleOrder = () => {
    if (cart.length === 0) return alert('Giỏ hàng trống!');

    let message = "📦 ĐƠN HÀNG MỚI - SHOP IN 3D\n\n";
