      </div>

      {/* Navigation */}
      <nav className="sticky top-0 z-40 glass border-b border-[#eeeeea] px-8 py-5">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-6">
            <button className="lg:hidden p-2 text-slate-400">
              <Menu size={22} />
            </button>
            <div className="flex items-center gap-3.5 group cursor-pointer">
              <div className="w-11 h-11 rounded-2xl gentle-gradient flex items-center justify-center text-white shadow-md transform group-hover:rotate-3 transition-transform">
                <Box size={24} strokeWidth={2.2} />
              </div>
              <div className="flex flex-col">
                <h1 className="text-lg font-black tracking-tight leading-none text-slate-700">
                    SHOPIN<span className="text-[#88a088]">3D</span>
                </h1>
                <span className="text-[8px] uppercase font-bold text-slate-400 tracking-[0.4em] mt-1">Creative Lab</span>
              </div>
            </div>
          </div>

          <div className="hidden lg:flex items-center gap-12">
