                <a key={item} href="#" className="text-[11px] font-bold text-slate-500 hover:text-slate-800 transition-colors uppercase tracking-[0.2em]">{item}</a>
            ))}
          </div>

          <div className="flex items-center gap-3">
            <div className="flex items-center bg-[#f5f5f2] rounded-2xl px-1 border border-[#eeeeea]">
