                  onClick={() => setIsWishlistOpen(true)}
                  className="relative p-3 text-slate-400 hover:text-rose-400 transition-colors"
                >
                <Heart size={20} className={wishlist.length > 0 ? "fill-rose-400 text-rose-400" : ""} />
                {wishlist.length > 0 && (
                    <span className="absolute top-2 right-2 w-4 h-4 bg-rose-400 text-white text-[8px] font-black rounded-full flex items-center justify-center border-2 border-[#f5f5f2]">
                      {wishlist.length}
