import React, { useState, useRef, useEffect } from 'react';
import { Trophy, X, PartyPopper, Sparkles } from 'lucide-react';

interface LuckySpinProps {
  onWin: (discount: number) => void;
  onClose: () => void;
}

export const LuckySpin: React.FC<LuckySpinProps> = ({ onWin, onClose }) => {
  const [isSpinning, setIsSpinning] = useState(false);
  const [result, setResult] = useState<number | null>(null);
  const slotRef = useRef<HTMLDivElement>(null);

  const rewards = [0, 5, 10, 15, 20];
  const items = [...rewards, ...rewards, ...rewards, ...rewards];

  const handleSpin = () => {
    if (isSpinning) return;
    setIsSpinning(true);
    setResult(null);

    const winningIdx = Math.floor(Math.random() * rewards.length);
    const winValue = rewards[winningIdx];

    const itemHeight = 100;
    const finalIdx = (items.length - rewards.length) + winningIdx;
    const offset = finalIdx * itemHeight;

    if (slotRef.current) {
      slotRef.current.style.transition = 'none';
      slotRef.current.style.transform = 'translateY(0)';
      slotRef.current.offsetHeight;

      slotRef.current.style.transition = 'transform 4.5s cubic-bezier(0.12, 0.8, 0.1, 1)';
      slotRef.current.style.transform = `translateY(-${offset}px)`;
    }

    setTimeout(() => {
      setIsSpinning(false);
      setResult(winValue);
      onWin(winValue);
    }, 4700);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-8 bg-slate-900/10 backdrop-blur-sm">
      <div className="relative bg-[#fafaf7] w-full max-w-md p-12 rounded-[3rem] text-center shadow-2xl overflow-hidden border border-[#eeeeea]">
        <div className="absolute top-0 left-0 w-full h-1.5 gentle-gradient opacity-60" />

        <button 
          onClick={onClose}
          className="absolute top-8 right-8 p-2.5 text-slate-300 hover:text-slate-600 hover:bg-white rounded-2xl transition-all border border-transparent hover:border-[#eeeeea]"
        >
          <X size={22} />
        </button>

        <div className="inline-flex items-center justify-center w-20 h-20 bg-white rounded-[2rem] mb-8 text-[#88a088] shadow-sm border border-[#eeeeea] floating">
          <Trophy size={36} strokeWidth={1.5} />
        </div>

        <h2 className="text-3xl font-bold mb-3 text-slate-700 tracking-tight">Hộp quà May mắn</h2>
        <p className="text-slate-400 mb-12 font-medium text-sm leading-relaxed">Cơ hội nhận mã giảm giá lên đến 20% <br/> áp dụng cho mọi đơn hàng hôm nay.</p>

        <div className="relative mb-12">
          <div className="w-44 h-[100px] mx-auto border-4 border-white rounded-[2.5rem] overflow-hidden bg-white shadow-inner relative border border-[#eeeeea]">
            <div ref={slotRef} className="flex flex-col">
              {items.map((val, i) => (
                <div key={i} className={`h-[100px] flex items-center justify-center text-4xl font-bold ${val > 0 ? 'text-[#88a088]' : 'text-slate-200'}`}>
                  {val}%
                </div>
              ))}
            </div>
            {/* Soft Indicator Lines */}
            <div className="absolute inset-x-0 top-1/2 -translate-y-1/2 flex items-center justify-between px-3 pointer-events-none opacity-40">
                <div className="w-1 h-5 bg-[#88a088] rounded-full" />
                <div className="w-1 h-5 bg-[#88a088] rounded-full" />
            </div>
          </div>

          <div className="absolute -top-4 -right-1 text-slate-300 animate-pulse"><Sparkles size={20}/></div>
          <div className="absolute -bottom-2 -left-4 text-slate-300 animate-bounce"><PartyPopper size={20}/></div>
        </div>

        <button
          onClick={handleSpin}
          disabled={isSpinning || result !== null}
          className={`w-full py-5 rounded-[1.5rem] font-bold text-[11px] uppercase tracking-[0.25em] transition-all transform active:scale-95 ${
            isSpinning || result !== null
              ? 'bg-white text-slate-300 border border-[#eeeeea] cursor-not-allowed'
              : 'bg-slate-800 text-white shadow-xl hover:bg-slate-700'
          }`}
        >
          {isSpinning ? 'Đang quay...' : result !== null ? 'Hoàn thành' : 'Quay ngay'}
        </button>

        {result !== null && (
          <div className="mt-10 p-8 bg-white/60 rounded-[2.5rem] border border-[#eeeeea] animate-in fade-in zoom-in duration-700">
            {result > 0 ? (
              <>
                <p className="text-[#88a088] font-bold text-sm mb-2 uppercase tracking-[0.1em]">Chúc mừng bạn!</p>
                <p className="text-slate-500 font-medium text-xs leading-relaxed">Mã ưu đãi <span className="text-slate-800 font-black text-xl mx-1">{result}%</span> đã được kích hoạt trong giỏ hàng.</p>
              </>
            ) : (
              <>
                <p className="text-slate-500 font-bold mb-1 text-sm">Cảm ơn bạn đã tham gia!</p>
                <p className="text-slate-400 text-[11px] font-medium leading-relaxed">Hãy quay lại vào ngày mai để thử vận may khác nhé. 🍀</p>
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Product, CartItem } from '../types';
import { SIZES, MATERIALS } from '../constants';
import { ShoppingCart, Check, Heart, ArrowRight } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  isWishlisted: boolean;
  onAddToCart: (item: CartItem) => void;
  onToggleWishlist: (product: Product) => void;
}

export const ProductCard: React.FC<ProductCardProps> = ({ 
  product, 
  isWishlisted, 
  onAddToCart, 
  onToggleWishlist 
}) => {
  const [sizeIdx, setSizeIdx] = useState(0);
  const [materialIdx, setMaterialIdx] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [isAdding, setIsAdding] = useState(false);

  const currentPrice = useMemo(() => {
    return Math.round(
      product.basePrice * 
      SIZES[sizeIdx].multiplier * 
      MATERIALS[materialIdx].multiplier * 
      quantity
    );
  }, [product.basePrice, sizeIdx, materialIdx, quantity]);

  const handleAdd = () => {
    setIsAdding(true);
    onAddToCart({
      id: `${product.id}-${Date.now()}`,
      productId: product.id,
      name: product.name,
      size: SIZES[sizeIdx].label,
      sizeMultiplier: SIZES[sizeIdx].multiplier,
      material: MATERIALS[materialIdx].label,
      materialMultiplier: MATERIALS[materialIdx].multiplier,
      quantity,
      price: currentPrice
    });
    setTimeout(() => setIsAdding(false), 2000);
  };

  return (
    <div className="group relative bg-white rounded-[2.5rem] overflow-hidden card-shadow border border-[#f1f1ee] flex flex-col" id={`product-${product.id}`}>
      {/* Heart Button with pop effect */}
      <button 
        onClick={() => onToggleWishlist(product)}
        className={`absolute top-6 right-6 z-10 p-3 rounded-full bg-white/80 backdrop-blur-md shadow-sm border border-white/50 transition-all duration-300 springy hover:shadow-md ${
          isWishlisted ? 'text-rose-400' : 'text-slate-300 hover:text-rose-400'
        }`}
      >
        <Heart size={20} fill={isWishlisted ? "currentColor" : "none"} strokeWidth={isWishlisted ? 0 : 2} />
      </button>

      {/* Image Section with hover zoom */}
      <div className="relative aspect-[4/3] bg-[#f9f9f6] overflow-hidden cursor-pointer">
        <img 
          src={product.image} 
          alt={product.name}
