          {/* Price & Quantity with elastic controls */}
          <div className="flex items-center justify-between pt-6 border-t border-[#f5f5f2]">
            <div className="flex flex-col">
              <span className="text-2xl font-black text-slate-800 tracking-tighter">
                {currentPrice.toLocaleString()}đ
              </span>
              <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">Giá hoàn thiện</span>
            </div>
            <div className="flex items-center bg-[#fafaf7] rounded-2xl p-1.5 gap-1 border border-[#eeeeea] shadow-sm">
                <button 
                    onClick={() => setQuantity(q => Math.max(1, q - 1))}
                    className="w-8 h-8 flex items-center justify-center bg-white rounded-xl text-slate-400 hover:text-slate-800 transition-all springy border border-transparent hover:border-[#eeeeea]"
                >-</button>
                <span className="w-8 text-center text-xs font-black text-slate-700">{quantity}</span>
                <button 
                    onClick={() => setQuantity(q => q + 1)}
                    className="w-8 h-8 flex items-center justify-center bg-white rounded-xl text-slate-400 hover:text-slate-800 transition-all springy border border-transparent hover:border-[#eeeeea]"
                >+</button>
            </div>
          </div>

          <button
            onClick={handleAdd}
            disabled={isAdding}
            className={`group/btn w-full py-4.5 rounded-[1.5rem] flex items-center justify-center gap-3 font-black text-[11px] tracking-[0.15em] transition-all duration-500 springy ${
              isAdding 
                ? 'bg-[#88a088] text-white shadow-[#88a088]/20 shadow-xl' 
                : 'bg-slate-800 text-white hover:bg-slate-900 shadow-slate-900/10 shadow-xl'
            }`}
          >
            {isAdding ? (
              <div className="flex items-center gap-2 animate-in fade-in zoom-in duration-300">
                <Check size={18} strokeWidth={3} />
