            <button className="lg:hidden p-3 text-slate-400 hover:bg-[#fafaf7] rounded-2xl transition-all springy">
              <Menu size={22} />
            </button>
            <div className="flex items-center gap-4 group cursor-pointer" onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}>
              <div className="w-12 h-12 rounded-[1.25rem] gentle-gradient flex items-center justify-center text-white shadow-lg transform group-hover:rotate-6 transition-transform duration-500 ease-out">
                <Box size={24} strokeWidth={2.5} />
              </div>
              <div className="flex flex-col">
                <h1 className="text-xl font-black tracking-tighter leading-none text-slate-800">
                    SHOPIN<span className="text-[#88a088]">3D</span>
                </h1>
                <span className="text-[9px] uppercase font-black text-slate-400 tracking-[0.4em] mt-1.5">Creative Lab</span>
              </div>
            </div>
          </div>

          <div className="hidden lg:flex items-center gap-12">
            {['Sản phẩm', 'Xưởng in', 'Hợp tác', 'Liên hệ'].map(item => (
