import React, { useState, useMemo } from 'react';
import { Product, CartItem } from '../types';
import { SIZES, MATERIALS } from '../constants';
import { ShoppingCart, Check, Heart, ArrowRight } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  isWishlisted: boolean;
  onAddToCart: (item: CartItem) => void;
  onToggleWishlist: (product: Product) => void;
}

export const ProductCard: React.FC<ProductCardProps> = ({ 
  product, 
  isWishlisted, 
  onAddToCart, 
  onToggleWishlist 
}) => {
  const [sizeIdx, setSizeIdx] = useState(0);
  const [materialIdx, setMaterialIdx] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [isAdding, setIsAdding] = useState(false);

  const currentPrice = useMemo(() => {
    return Math.round(
      product.basePrice * 
      SIZES[sizeIdx].multiplier * 
      MATERIALS[materialIdx].multiplier * 
      quantity
    );
  }, [product.basePrice, sizeIdx, materialIdx, quantity]);

  const handleAdd = () => {
    setIsAdding(true);
    onAddToCart({
      id: `${product.id}-${Date.now()}`,
      productId: product.id,
      name: product.name,
      size: SIZES[sizeIdx].label,
      sizeMultiplier: SIZES[sizeIdx].multiplier,
      material: MATERIALS[materialIdx].label,
      materialMultiplier: MATERIALS[materialIdx].multiplier,
      quantity,
      price: currentPrice
    });
    setTimeout(() => setIsAdding(false), 1800);
  };

  return (
    <div className="group relative bg-white rounded-[2.5rem] overflow-hidden card-shadow border border-avocado-100/50 flex flex-col transition-all duration-300" id={`product-${product.id}`}>
      {/* Wishlist Button */}
      <button 
        onClick={() => onToggleWishlist(product)}
        className={`absolute top-6 right-6 z-10 p-3 rounded-full bg-white/90 backdrop-blur-md shadow-sm border border-avocado-100 transition-all duration-300 springy hover:shadow-md ${
          isWishlisted ? 'text-rose-400' : 'text-avocado-300 hover:text-rose-400'
        }`}
        aria-label="Add to wishlist"
      >
        <Heart size={20} fill={isWishlisted ? "currentColor" : "none"} strokeWidth={isWishlisted ? 0 : 2} />
      </button>

      {/* Product Image */}
      <div className="relative aspect-[4/3] bg-avocado-50/50 overflow-hidden cursor-pointer group-hover:bg-avocado-50 transition-colors duration-500">
        <img 
          src={product.image} 
          alt={product.name}
          className="w-full h-full object-cover transition-transform duration-700 ease-out group-hover:scale-110"
        />
        {product.badge && (
          <div className="absolute top-6 left-6 px-4 py-1.5 bg-avocado-500/90 text-white text-[10px] font-black tracking-widest rounded-xl uppercase backdrop-blur-md shadow-sm">
            {product.badge}
          </div>
        )}
      </div>

      <div className="p-8 flex-1 flex flex-col">
        <h3 className="text-xl font-bold mb-6 text-avocado-900 tracking-tight group-hover:text-avocado-700 transition-colors">
          {product.name}
        </h3>

        <div className="space-y-6 flex-1">
          {/* Size Selector */}
          <div>
            <label className="block text-[10px] font-bold text-avocado-400 uppercase tracking-[0.2em] mb-3 ml-1">Kích thước</label>
            <div className="flex gap-2 p-1.5 bg-avocado-50/50 rounded-2xl border border-avocado-100">
              {SIZES.map((s, idx) => (
                <button
                  key={s.label}
                  onClick={() => setSizeIdx(idx)}
                  className={`flex-1 py-2.5 text-[11px] font-black rounded-xl transition-all duration-300 springy ${
                    sizeIdx === idx 
                      ? 'bg-white text-avocado-700 shadow-sm border border-avocado-100' 
                      : 'text-avocado-400 hover:text-avocado-600'
                  }`}
                >
                  {s.label}
                </button>
              ))}
            </div>
          </div>

          {/* Material Selector */}
          <div>
            <label className="block text-[10px] font-bold text-avocado-400 uppercase tracking-[0.2em] mb-3 ml-1">Vật liệu</label>
            <div className="flex gap-2">
              {MATERIALS.map((m, idx) => (
                <button
                  key={m.label}
                  onClick={() => setMaterialIdx(idx)}
                  className={`flex-1 py-2.5 text-[11px] font-black rounded-2xl border transition-all duration-300 springy ${
                    materialIdx === idx 
                      ? 'bg-avocado-100/50 border-avocado-300/50 text-avocado-700 shadow-sm' 
                      : 'bg-white border-avocado-100/50 text-avocado-300 hover:border-avocado-200 hover:text-avocado-500'
                  }`}
                >
                  {m.label.split(' ')[0]}
                </button>
              ))}
            </div>
          </div>

          {/* Pricing & Quantity Controls */}
          <div className="flex items-center justify-between pt-6 border-t border-avocado-100/50">
            <div className="flex flex-col">
              <span className="text-2xl font-black text-avocado-900 tracking-tighter">
                {currentPrice.toLocaleString()}đ
              </span>
              <span className="text-[9px] text-avocado-400 font-bold uppercase tracking-widest">Giá dự kiến</span>
            </div>
            <div className="flex items-center bg-avocado-50/50 rounded-2xl p-1.5 gap-1 border border-avocado-100 shadow-sm">
                <button 
                    onClick={() => setQuantity(q => Math.max(1, q - 1))}
                    className="w-8 h-8 flex items-center justify-center bg-white rounded-xl text-avocado-400 hover:text-avocado-900 transition-all springy border border-transparent hover:border-avocado-100"
                >-</button>
                <span className="w-8 text-center text-xs font-black text-avocado-700">{quantity}</span>
                <button 
                    onClick={() => setQuantity(q => q + 1)}
                    className="w-8 h-8 flex items-center justify-center bg-white rounded-xl text-avocado-400 hover:text-avocado-900 transition-all springy border border-transparent hover:border-avocado-100"
                >+</button>
            </div>
          </div>

          <button
            onClick={handleAdd}
            disabled={isAdding}
            className={`group/btn w-full py-4.5 rounded-[1.5rem] flex items-center justify-center gap-3 font-black text-[11px] tracking-[0.15em] transition-all duration-500 springy shadow-lg ${
              isAdding 
                ? 'bg-avocado-500 text-white shadow-avocado-500/20' 
                : 'bg-avocado-900 text-white hover:bg-avocado-800 shadow-avocado-900/10'
            }`}
          >
            {isAdding ? (
              <div className="flex items-center gap-2 check-pop">
                <Check size={18} strokeWidth={3} />
                ĐÃ THÊM
              </div>
            ) : (
              <>
                <ShoppingCart size={18} strokeWidth={2.5} className="group-hover/btn:-translate-x-1 transition-transform" />
                MUA NGAY
                <ArrowRight size={16} strokeWidth={2.5} className="opacity-0 group-hover/btn:opacity-100 group-hover/btn:translate-x-1 transition-all" />
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
