import React, { useState, useRef, useEffect } from 'react';
import { Trophy, X, PartyPopper, Sparkles } from 'lucide-react';

interface LuckySpinProps {
  onWin: (discount: number) => void;
  onClose: () => void;
}

export const LuckySpin: React.FC<LuckySpinProps> = ({ onWin, onClose }) => {
  const [isSpinning, setIsSpinning] = useState(false);
  const [result, setResult] = useState<number | null>(null);
  const slotRef = useRef<HTMLDivElement>(null);

  const rewards = [0, 5, 10, 15, 20];
  const items = [...rewards, ...rewards, ...rewards, ...rewards];

  const handleSpin = () => {
    if (isSpinning) return;
    setIsSpinning(true);
    setResult(null);

    const winningIdx = Math.floor(Math.random() * rewards.length);
    const winValue = rewards[winningIdx];

    const itemHeight = 100;
    const finalIdx = (items.length - rewards.length) + winningIdx;
    const offset = finalIdx * itemHeight;

    if (slotRef.current) {
      slotRef.current.style.transition = 'none';
      slotRef.current.style.transform = 'translateY(0)';
      slotRef.current.offsetHeight;

      slotRef.current.style.transition = 'transform 4.5s cubic-bezier(0.12, 0.8, 0.1, 1)';
      slotRef.current.style.transform = `translateY(-${offset}px)`;
    }

    setTimeout(() => {
      setIsSpinning(false);
      setResult(winValue);
      onWin(winValue);
    }, 4700);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-8 bg-avocado-900/10 backdrop-blur-md animate-in fade-in duration-500">
      <div className="relative bg-white w-full max-w-md p-12 rounded-[3rem] text-center shadow-2xl overflow-hidden border border-avocado-100 animate-in zoom-in duration-500">
        <div className="absolute top-0 left-0 w-full h-1.5 avocado-gradient opacity-60" />

        <button 
          onClick={onClose}
          className="absolute top-8 right-8 p-2.5 text-avocado-300 hover:text-avocado-900 hover:bg-avocado-50 rounded-2xl transition-all border border-transparent hover:border-avocado-100 springy"
        >
          <X size={22} />
        </button>

        <div className="inline-flex items-center justify-center w-20 h-20 bg-avocado-50 rounded-[2rem] mb-8 text-avocado-500 shadow-sm border border-avocado-100 floating">
          <Trophy size={36} strokeWidth={1.5} />
        </div>

        <h2 className="text-3xl font-bold mb-3 text-avocado-900 tracking-tight">Hộp quà May mắn</h2>
        <p className="text-avocado-500/70 mb-12 font-medium text-sm leading-relaxed">Nhận ưu đãi giảm giá lên đến 20% <br/> áp dụng trực tiếp cho giỏ hàng của bạn.</p>

        <div className="relative mb-12">
          <div className="w-44 h-[100px] mx-auto border-4 border-avocado-50 rounded-[2.5rem] overflow-hidden bg-avocado-50 shadow-inner relative border border-avocado-100">
            <div ref={slotRef} className="flex flex-col">
              {items.map((val, i) => (
                <div key={i} className={`h-[100px] flex items-center justify-center text-4xl font-black ${val > 0 ? 'text-avocado-600' : 'text-avocado-200'}`}>
                  {val}%
                </div>
              ))}
            </div>
            {/* Center Indicator */}
            <div className="absolute inset-x-0 top-1/2 -translate-y-1/2 flex items-center justify-between px-3 pointer-events-none opacity-40">
                <div className="w-1.5 h-6 bg-avocado-500 rounded-full" />
                <div className="w-1.5 h-6 bg-avocado-500 rounded-full" />
            </div>
          </div>

          <div className="absolute -top-4 -right-1 text-avocado-300 animate-pulse"><Sparkles size={20}/></div>
          <div className="absolute -bottom-2 -left-4 text-avocado-300 animate-bounce"><PartyPopper size={20}/></div>
        </div>

        <button
          onClick={handleSpin}
          disabled={isSpinning || result !== null}
          className={`w-full py-5 rounded-[1.5rem] font-bold text-[11px] uppercase tracking-[0.25em] transition-all transform active:scale-95 springy shadow-lg ${
            isSpinning || result !== null
              ? 'bg-avocado-50 text-avocado-300 border border-avocado-100 cursor-not-allowed'
              : 'bg-avocado-900 text-white hover:bg-avocado-800'
          }`}
        >
          {isSpinning ? 'Đang xoay...' : result !== null ? 'Hoàn thành' : 'Quay thưởng ngay'}
        </button>

        {result !== null && (
          <div className="mt-10 p-8 bg-avocado-50/50 rounded-[2.5rem] border border-avocado-100 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {result > 0 ? (
              <>
                <p className="text-avocado-700 font-bold text-sm mb-2 uppercase tracking-[0.1em] check-pop flex items-center justify-center gap-2">
                   <PartyPopper size={16} /> Tuyệt vời!
                </p>
                <p className="text-avocado-500 font-medium text-xs leading-relaxed">Bạn đã nhận được ưu đãi <span className="text-avocado-900 font-black text-xl mx-1">{result}%</span></p>
              </>
            ) : (
              <>
                <p className="text-avocado-500 font-bold mb-1 text-sm">Hẹn bạn lần sau!</p>
                <p className="text-avocado-400 text-[11px] font-medium leading-relaxed">Đừng buồn, ưu đãi khác vẫn đang chờ bạn khám phá. 🍀</p>
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Product, CartItem } from '../types';
import { SIZES, MATERIALS } from '../constants';
import { ShoppingCart, Check, Heart, ArrowRight } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  isWishlisted: boolean;
  onAddToCart: (item: CartItem) => void;
  onToggleWishlist: (product: Product) => void;
}

export const ProductCard: React.FC<ProductCardProps> = ({ 
  product, 
  isWishlisted, 
  onAddToCart, 
  onToggleWishlist 
}) => {
  const [sizeIdx, setSizeIdx] = useState(0);
  const [materialIdx, setMaterialIdx] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [isAdding, setIsAdding] = useState(false);

  const currentPrice = useMemo(() => {
    return Math.round(
      product.basePrice * 
      SIZES[sizeIdx].multiplier * 
      MATERIALS[materialIdx].multiplier * 
      quantity
    );
  }, [product.basePrice, sizeIdx, materialIdx, quantity]);

  const handleAdd = () => {
    setIsAdding(true);
    onAddToCart({
      id: `${product.id}-${Date.now()}`,
      productId: product.id,
      name: product.name,
      size: SIZES[sizeIdx].label,
      sizeMultiplier: SIZES[sizeIdx].multiplier,
      material: MATERIALS[materialIdx].label,
      materialMultiplier: MATERIALS[materialIdx].multiplier,
      quantity,
      price: currentPrice
    });
    setTimeout(() => setIsAdding(false), 1800);
  };

  return (
    <div className="group relative bg-white rounded-[2.5rem] overflow-hidden card-shadow border border-avocado-200/40 flex flex-col transition-all duration-300" id={`product-${product.id}`}>
      {/* Wishlist Button */}
      <button 
        onClick={() => onToggleWishlist(product)}
        className={`absolute top-6 right-6 z-10 p-3 rounded-full bg-white/95 backdrop-blur-md shadow-sm border border-avocado-200 transition-all duration-300 springy hover:shadow-md ${
          isWishlisted ? 'text-rose-500' : 'text-avocado-400 hover:text-rose-500'
        }`}
        aria-label="Thêm vào danh sách yêu thích"
      >
        <Heart size={20} fill={isWishlisted ? "currentColor" : "none"} strokeWidth={isWishlisted ? 0 : 2} />
      </button>

      {/* Product Image */}
      <div className="relative aspect-[4/3] bg-avocado-50 overflow-hidden cursor-pointer group-hover:bg-avocado-100/30 transition-colors duration-500">
        <img 
          src={product.image} 
          alt={product.name}
          className="w-full h-full object-cover transition-transform duration-700 ease-out group-hover:scale-110"
        />
        {product.badge && (
          <div className="absolute top-6 left-6 px-4 py-1.5 bg-avocado-700 text-white text-[10px] font-extrabold tracking-widest rounded-xl uppercase shadow-lg">
            {product.badge}
          </div>
        )}
      </div>

      <div className="p-8 flex-1 flex flex-col">
        <h3 className="text-2xl font-extrabold mb-6 text-avocado-900 tracking-tight leading-tight group-hover:text-avocado-700 transition-colors">
          {product.name}
        </h3>

        <div className="space-y-7 flex-1">
          {/* Size Selector */}
          <div>
            <label className="block text-[11px] font-black text-avocado-700 uppercase tracking-[0.15em] mb-3 ml-1">Kích thước</label>
            <div className="flex gap-2 p-1.5 bg-avocado-100/40 rounded-2xl border border-avocado-200/60 selection-pressed">
              {SIZES.map((s, idx) => (
                <button
                  key={s.label}
                  onClick={() => setSizeIdx(idx)}
                  className={`flex-1 py-3 text-[12px] font-extrabold rounded-xl transition-all duration-200 springy ${
                    sizeIdx === idx 
                      ? 'bg-white text-avocado-900 shadow-md border border-avocado-200' 
                      : 'text-avocado-500 hover:text-avocado-800'
                  }`}
                >
                  {s.label}
                </button>
              ))}
            </div>
          </div>

          {/* Material Selector */}
          <div>
            <label className="block text-[11px] font-black text-avocado-700 uppercase tracking-[0.15em] mb-3 ml-1">Vật liệu in</label>
            <div className="flex gap-3">
              {MATERIALS.map((m, idx) => (
                <button
                  key={m.label}
                  onClick={() => setMaterialIdx(idx)}
                  className={`flex-1 py-3 px-4 text-[12px] font-extrabold rounded-2xl border-2 transition-all duration-200 springy ${
                    materialIdx === idx 
                      ? 'bg-avocado-100 border-avocado-500 text-avocado-900 shadow-sm' 
                      : 'bg-white border-avocado-100 text-avocado-400 hover:border-avocado-300 hover:text-avocado-600'
                  }`}
                >
                  {m.label.split(' ')[0]}
                </button>
              ))}
            </div>
          </div>

          {/* Pricing & Quantity Controls */}
          <div className="flex items-center justify-between pt-7 border-t border-avocado-200/50">
            <div className="flex flex-col">
              <span className="text-[10px] text-avocado-500 font-bold uppercase tracking-widest mb-1">Giá hoàn thiện</span>
              <span className="text-3xl font-black text-avocado-900 tracking-tighter">
                {currentPrice.toLocaleString()}đ
              </span>
            </div>
            <div className="flex items-center bg-avocado-100/50 rounded-2xl p-1.5 gap-1 border border-avocado-200 shadow-sm">
                <button 
                    onClick={() => setQuantity(q => Math.max(1, q - 1))}
                    className="w-10 h-10 flex items-center justify-center bg-white rounded-xl text-avocado-600 hover:text-avocado-900 transition-all springy border border-avocado-200 shadow-sm"
                    aria-label="Giảm số lượng"
                >-</button>
                <span className="w-10 text-center text-sm font-black text-avocado-900">{quantity}</span>
                <button 
                    onClick={() => setQuantity(q => q + 1)}
                    className="w-10 h-10 flex items-center justify-center bg-white rounded-xl text-avocado-600 hover:text-avocado-900 transition-all springy border border-avocado-200 shadow-sm"
                    aria-label="Tăng số lượng"
                >+</button>
            </div>
          </div>

          <button
            onClick={handleAdd}
            disabled={isAdding}
            className={`group/btn w-full py-5 rounded-[1.75rem] flex items-center justify-center gap-3 font-black text-[12px] tracking-[0.2em] transition-all duration-500 springy shadow-xl ${
              isAdding 
                ? 'bg-emerald-600 text-white shadow-emerald-500/20' 
                : 'bg-avocado-900 text-white hover:bg-black shadow-avocado-900/20'
            }`}
          >
            {isAdding ? (
              <div className="flex items-center gap-2 check-pop">
                <Check size={20} strokeWidth={3} />
                ĐÃ THÊM VÀO GIỎ
              </div>
            ) : (
              <>
                <ShoppingCart size={20} strokeWidth={2.5} className="group-hover/btn:-translate-x-1 transition-transform" />
                ĐẶT MUA NGAY
                <ArrowRight size={18} strokeWidth={2.5} className="opacity-0 group-hover/btn:opacity-100 group-hover/btn:translate-x-1 transition-all" />
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
