        <div className="inline-flex items-center justify-center w-24 h-24 bg-avocado-50 rounded-[2.5rem] mb-10 text-avocado-600 shadow-sm border border-avocado-200 floating">
          <Trophy size={42} strokeWidth={1.5} />
        </div>

        <h2 className="text-4xl font-black mb-4 text-avocado-900 tracking-tight">Hộp quà May mắn</h2>
        <p className="text-avocado-800 mb-14 font-medium text-base leading-relaxed opacity-80">Nhận ưu đãi giảm giá lên đến 20% <br/> áp dụng trực tiếp cho đơn hàng của bạn.</p>

        <div className="relative mb-14">
