import React, { useState, useMemo } from 'react';
import { Product, CartItem } from '../types';
import { SIZES, MATERIALS } from '../constants';
import { ShoppingCart, Check, Heart, ArrowRight } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  isWishlisted: boolean;
  onAddToCart: (item: CartItem) => void;
  onToggleWishlist: (product: Product) => void;
}

export const ProductCard: React.FC<ProductCardProps> = ({ 
  product, 
  isWishlisted, 
  onAddToCart, 
  onToggleWishlist 
}) => {
  const [sizeIdx, setSizeIdx] = useState(0);
  const [materialIdx, setMaterialIdx] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [isAdding, setIsAdding] = useState(false);

  const currentPrice = useMemo(() => {
    return Math.round(
      product.basePrice * 
      SIZES[sizeIdx].multiplier * 
      MATERIALS[materialIdx].multiplier * 
      quantity
    );
  }, [product.basePrice, sizeIdx, materialIdx, quantity]);

  const handleAdd = () => {
    setIsAdding(true);
    onAddToCart({
      id: `${product.id}-${Date.now()}`,
      productId: product.id,
      name: product.name,
      size: SIZES[sizeIdx].label,
      sizeMultiplier: SIZES[sizeIdx].multiplier,
      material: MATERIALS[materialIdx].label,
      materialMultiplier: MATERIALS[materialIdx].multiplier,
      quantity,
      price: currentPrice
    });
    setTimeout(() => setIsAdding(false), 1200);
  };

  return (
    <div className="group relative bg-white rounded-[2rem] overflow-hidden card-shadow border border-avocado-100 flex flex-col h-full" id={`product-${product.id}`}>
      {/* Favorite Button */}
      <button 
        onClick={() => onToggleWishlist(product)}
        className={`absolute top-4 right-4 z-10 p-2.5 rounded-full bg-white/95 backdrop-blur-md shadow-sm border border-avocado-100 transition-all duration-200 springy ${
          isWishlisted ? 'text-rose-500' : 'text-avocado-300 hover:text-rose-500'
        }`}
        aria-label="Yêu thích"
      >
        <Heart size={18} fill={isWishlisted ? "currentColor" : "none"} strokeWidth={isWishlisted ? 0 : 2} />
      </button>

      {/* Product Image Container */}
      <div className="relative aspect-[4/3] bg-avocado-50 overflow-hidden cursor-pointer">
        <img 
          src={product.image} 
          alt={product.name}
          className="w-full h-full object-cover transition-transform duration-500 ease-out group-hover:scale-105"
        />
        {product.badge && (
          <div className="absolute top-4 left-4 px-3 py-1 bg-avocado-700 text-white text-[9px] font-black tracking-widest rounded-lg uppercase shadow-md">
            {product.badge}
          </div>
        )}
      </div>

      <div className="p-6 flex-1 flex flex-col">
        <h3 className="text-xl font-bold mb-4 text-avocado-900 tracking-tight leading-snug">
          {product.name}
        </h3>

        <div className="space-y-5 mb-6">
          {/* Size Selector */}
          <div>
            <label className="block text-[10px] font-black text-avocado-600 uppercase tracking-widest mb-2.5 ml-0.5">Kích thước</label>
            <div className="flex gap-1.5 p-1 bg-avocado-50/50 rounded-xl border border-avocado-100">
              {SIZES.map((s, idx) => (
                <button
                  key={s.label}
                  onClick={() => setSizeIdx(idx)}
                  className={`flex-1 py-2 text-[11px] font-bold rounded-lg transition-all duration-200 ${
                    sizeIdx === idx 
                      ? 'bg-white text-avocado-900 shadow-sm border border-avocado-200' 
                      : 'text-avocado-400 hover:text-avocado-700'
                  }`}
                >
                  {s.label}
                </button>
              ))}
            </div>
          </div>

          {/* Material Selector */}
          <div>
            <label className="block text-[10px] font-black text-avocado-600 uppercase tracking-widest mb-2.5 ml-0.5">Vật liệu</label>
            <div className="flex gap-2">
              {MATERIALS.map((m, idx) => (
                <button
                  key={m.label}
                  onClick={() => setMaterialIdx(idx)}
                  className={`flex-1 py-2.5 px-2 text-[11px] font-bold rounded-xl border transition-all duration-200 ${
                    materialIdx === idx 
                      ? 'bg-avocado-100 border-avocado-400 text-avocado-900' 
                      : 'bg-white border-avocado-100 text-avocado-400 hover:border-avocado-200 hover:text-avocado-600'
                  }`}
                >
                  {m.label.split(' ')[0]}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Footer of card - Always attached */}
        <div className="mt-auto pt-5 border-t border-avocado-50 flex flex-col gap-4">
          <div className="flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[9px] text-avocado-400 font-bold uppercase tracking-widest mb-0.5">Hoàn thiện</span>
              <span className="text-2xl font-black text-avocado-900 tracking-tighter">
                {currentPrice.toLocaleString()}đ
              </span>
            </div>
            <div className="flex items-center bg-avocado-50 rounded-lg p-1 gap-0.5 border border-avocado-100">
                <button 
                    onClick={() => setQuantity(q => Math.max(1, q - 1))}
                    className="w-8 h-8 flex items-center justify-center bg-white rounded-md text-avocado-600 hover:text-avocado-900 transition-all springy shadow-sm border border-avocado-100"
                >-</button>
                <span className="w-8 text-center text-xs font-black text-avocado-900">{quantity}</span>
                <button 
                    onClick={() => setQuantity(q => q + 1)}
                    className="w-8 h-8 flex items-center justify-center bg-white rounded-md text-avocado-600 hover:text-avocado-900 transition-all springy shadow-sm border border-avocado-100"
                >+</button>
            </div>
          </div>

          <button
            onClick={handleAdd}
            disabled={isAdding}
            className={`w-full py-3.5 rounded-xl flex items-center justify-center gap-2.5 font-black text-[11px] tracking-widest transition-all duration-300 springy shadow-md ${
              isAdding 
                ? 'bg-emerald-600 text-white shadow-none' 
                : 'bg-avocado-900 text-white hover:bg-black shadow-avocado-900/5'
            }`}
          >
            {isAdding ? (
              <div className="flex items-center gap-2 check-pop">
                <Check size={16} strokeWidth={3} />
                ĐÃ THÊM
              </div>
            ) : (
              <>
                <ShoppingCart size={16} strokeWidth={2.5} />
                ĐẶT MUA NGAY
                <ArrowRight size={14} strokeWidth={2.5} className="ml-0.5" />
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

