                </h1>
                <span className="text-[8px] uppercase font-black text-avocado-500 tracking-[0.35em] mt-1 leading-none">Studio Fresh</span>
              </div>
            </div>
          </div>

          <div className="hidden lg:flex items-center gap-10">
            {['Sản phẩm', 'Xưởng in', 'Câu chuyện', 'Liên hệ'].map(item => (
                <a key={item} href="#" className="relative text-[11px] font-black text-avocado-800 hover:text-avocado-600 transition-colors uppercase tracking-[0.2em] group py-1">
                  {item}
                  <span className="absolute bottom-0 left-0 w-0 h-0.5 bg-avocado-500 transition-all duration-300 group-hover:w-full" />
                </a>
