                <span className="text-[7px] uppercase font-bold text-theme-text opacity-50 tracking-[0.3em] leading-none">Creative Lab</span>
              </div>
            </div>
          </div>

          <div className="hidden lg:flex items-center gap-8">
            {['Sản phẩm', 'Xưởng in', 'Câu chuyện', 'Liên hệ'].map(item => (
              <a key={item} href="#" className="relative text-[10px] font-bold text-theme-text opacity-70 hover:opacity-100 uppercase tracking-[0.15em] group py-1">
