          </div>

          <div className="flex items-center gap-4">
            {/* Theme Toggle */}
            <div className="hidden sm:flex items-center bg-theme-text/5 rounded-full px-2 py-1 gap-1">
              {(['natural', 'minimalist', 'eco'] as ThemeType[]).map(t => (
