                >+</button>
            </div>
          </div>

          <button
            onClick={handleAdd}
            disabled={isAdding}
            className={`w-full py-3.5 rounded-xl flex items-center justify-center gap-2 font-black text-[10px] tracking-widest transition-all duration-300 springy ${
              isAdding 
