                <ShoppingCart size={16} strokeWidth={2.5} />
                ĐẶT MUA NGAY
                <ArrowRight size={14} strokeWidth={2.5} className="ml-0.5" />
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Trophy, X, PartyPopper, Sparkles } from 'lucide-react';

interface LuckySpinProps {
  onWin: (discount: number) => void;
  onClose: () => void;
}

export const LuckySpin: React.FC<LuckySpinProps> = ({ onWin, onClose }) => {
  const [isSpinning, setIsSpinning] = useState(false);
  const [result, setResult] = useState<number | null>(null);
  const slotRef = useRef<HTMLDivElement>(null);

  const rewards = [0, 5, 10, 15, 20];
  const items = [...rewards, ...rewards, ...rewards, ...rewards];

  const handleSpin = () => {
    if (isSpinning) return;
    setIsSpinning(true);
    setResult(null);

    const winningIdx = Math.floor(Math.random() * rewards.length);
    const winValue = rewards[winningIdx];

    const itemHeight = 80; // Standardized height for visibility
    const finalIdx = (items.length - rewards.length) + winningIdx;
    const offset = finalIdx * itemHeight;

    if (slotRef.current) {
      slotRef.current.style.transition = 'none';
      slotRef.current.style.transform = 'translateY(0)';
      slotRef.current.offsetHeight; // force reflow

      slotRef.current.style.transition = 'transform 4.5s cubic-bezier(0.1, 0.9, 0.2, 1)';
      slotRef.current.style.transform = `translateY(-${offset}px)`;
    }

    setTimeout(() => {
      setIsSpinning(false);
      setResult(winValue);
      onWin(winValue);
    }, 4700);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-theme-text/20 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="relative bg-white w-full max-w-sm p-8 rounded-[2rem] text-center shadow-2xl overflow-hidden border border-theme-border/10 animate-in zoom-in duration-300">
        <div className="absolute top-0 left-0 w-full h-1 bg-theme-accent opacity-80" />

        <button 
          onClick={onClose}
          className="absolute top-4 right-4 p-2 text-theme-text opacity-40 hover:opacity-100 transition-all rounded-lg hover:bg-theme-bg springy"
          aria-label="Đóng"
        >
          <X size={20} />
        </button>

        <div className="inline-flex items-center justify-center w-16 h-16 bg-theme-bg rounded-2xl mb-6 text-theme-accent border border-theme-border/5">
          <Trophy size={32} strokeWidth={1.5} />
        </div>

        <h2 className="text-2xl font-black mb-2 text-theme-text tracking-tight">Hộp Quà May Mắn</h2>
        <p className="text-theme-text opacity-60 mb-8 font-medium text-[13px] leading-relaxed">Nhận mã giảm giá lên đến 20% <br/> cho mọi ý tưởng in ấn của bạn.</p>

        <div className="relative mb-8">
          <div className="w-40 h-[80px] mx-auto border border-theme-border/10 rounded-2xl overflow-hidden bg-theme-bg/50 shadow-inner relative">
            <div ref={slotRef} className="flex flex-col">
              {items.map((val, i) => (
                <div key={i} className={`h-[80px] flex items-center justify-center text-3xl font-black ${val > 0 ? 'text-theme-accent' : 'text-theme-text opacity-10'}`}>
                  {val}%
                </div>
              ))}
            </div>
            {/* Center Pointer Indicator */}
            <div className="absolute inset-x-0 top-1/2 -translate-y-1/2 flex items-center justify-between px-2 pointer-events-none">
              <div className="w-1.5 h-1.5 bg-theme-accent rounded-full shadow-sm" />
              <div className="w-1.5 h-1.5 bg-theme-accent rounded-full shadow-sm" />
            </div>
          </div>

          <div className="absolute -top-3 -right-1 text-theme-accent/30 animate-pulse"><Sparkles size={16}/></div>
          <div className="absolute -bottom-3 -left-1 text-theme-accent/30 animate-bounce"><PartyPopper size={16}/></div>
        </div>

        <button
          onClick={handleSpin}
          disabled={isSpinning || result !== null}
          className={`w-full py-4 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all springy shadow-sm ${
            isSpinning || result !== null
              ? 'bg-theme-bg text-theme-text opacity-20 border border-theme-border/5 cursor-not-allowed'
              : 'bg-theme-text text-white hover:bg-black'
          }`}
        >
          {isSpinning ? 'ĐANG XOAY...' : result !== null ? 'HOÀN THÀNH' : 'THỬ VẬN MAY'}
        </button>

        {result !== null && (
          <div className="mt-6 p-4 bg-theme-bg/50 rounded-xl border border-theme-border/5 animate-in fade-in slide-in-from-bottom-2 duration-500">
            {result > 0 ? (
              <>
                <p className="text-emerald-700 font-black text-[11px] mb-1 tracking-wide uppercase flex items-center justify-center gap-2">
                   <PartyPopper size={14} /> CHÚC MỪNG!
                </p>
                <p className="text-theme-text font-bold text-[12px] opacity-80">Mã ưu đãi <span className="text-base font-black border-b-2 border-theme-accent">{result}%</span> đã được áp dụng.</p>
              </>
            ) : (
              <>
                <p className="text-theme-text opacity-40 font-black text-[11px] uppercase tracking-widest">HẸN LẦN SAU!</p>
                <p className="text-theme-text opacity-40 text-[11px] font-bold mt-1">Chúc bạn một ngày tốt lành! 🍀</p>
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

