import React, { useState, useMemo } from 'react';
import { Product, CartItem } from '../types';
import { SIZES, MATERIALS } from '../constants';
import { ShoppingCart, Check, Heart, ArrowRight } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  isWishlisted: boolean;
  onAddToCart: (item: CartItem) => void;
  onToggleWishlist: (product: Product) => void;
}

export const ProductCard: React.FC<ProductCardProps> = ({ 
  product, 
  isWishlisted, 
  onAddToCart, 
  onToggleWishlist 
}) => {
  const [sizeIdx, setSizeIdx] = useState(0);
  const [materialIdx, setMaterialIdx] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [isAdding, setIsAdding] = useState(false);

  const currentPrice = useMemo(() => {
    return Math.round(
      product.basePrice * 
      SIZES[sizeIdx].multiplier * 
      MATERIALS[materialIdx].multiplier * 
      quantity
    );
  }, [product.basePrice, sizeIdx, materialIdx, quantity]);

  const handleAdd = () => {
    setIsAdding(true);
    onAddToCart({
      id: `${product.id}-${Date.now()}`,
      productId: product.id,
      name: product.name,
      size: SIZES[sizeIdx].label,
      sizeMultiplier: SIZES[sizeIdx].multiplier,
      material: MATERIALS[materialIdx].label,
      materialMultiplier: MATERIALS[materialIdx].multiplier,
      quantity,
      price: currentPrice
    });
    setTimeout(() => setIsAdding(false), 1200);
  };

  return (
    <div className="group relative bg-white rounded-2xl overflow-hidden card-shadow flex flex-col h-full" id={`product-${product.id}`}>
      {/* Favorite Button */}
      <button 
        onClick={() => onToggleWishlist(product)}
        className={`absolute top-4 right-4 z-10 p-2.5 rounded-full bg-white/95 backdrop-blur-md shadow-sm border border-theme-border transition-all duration-200 springy ${
          isWishlisted ? 'text-theme-accent' : 'text-theme-text opacity-30 hover:opacity-100 hover:text-theme-accent'
        }`}
        aria-label="Yêu thích"
      >
        <Heart size={18} fill={isWishlisted ? "currentColor" : "none"} strokeWidth={isWishlisted ? 0 : 2} />
      </button>

      {/* Product Image Container */}
      <div className="relative aspect-[4/3] bg-theme-bg overflow-hidden cursor-pointer">
        <img 
          src={product.image} 
          alt={product.name}
          className="w-full h-full object-cover transition-transform duration-700 ease-out group-hover:scale-105"
        />
        {product.badge && (
          <div className="absolute top-4 left-4 px-3 py-1 bg-theme-text text-white text-[8px] font-black tracking-widest rounded-md uppercase">
            {product.badge}
          </div>
        )}
      </div>

      <div className="p-7 flex-1 flex flex-col">
        <h3 className="text-2xl font-black mb-5 text-theme-text tracking-tight leading-snug">
          {product.name}
        </h3>

        <div className="space-y-5 mb-8">
          {/* Size Selector */}
          <div>
            <label className="block text-[10px] font-bold text-theme-text opacity-40 uppercase tracking-widest mb-2.5 ml-0.5">Kích thước</label>
            <div className="flex gap-1.5 p-1 bg-theme-bg border border-theme-border rounded-xl">
              {SIZES.map((s, idx) => (
                <button
                  key={s.label}
                  onClick={() => setSizeIdx(idx)}
                  className={`flex-1 py-2 text-[11px] font-bold rounded-lg transition-all duration-200 ${
                    sizeIdx === idx 
                      ? 'bg-white text-theme-text shadow-sm border border-theme-border' 
                      : 'text-theme-text opacity-40 hover:opacity-70'
                  }`}
                >
                  {s.label}
                </button>
              ))}
            </div>
          </div>

          {/* Material Selector */}
          <div>
            <label className="block text-[10px] font-bold text-theme-text opacity-40 uppercase tracking-widest mb-2.5 ml-0.5">Vật liệu in</label>
            <div className="flex gap-2.5">
              {MATERIALS.map((m, idx) => (
                <button
                  key={m.label}
                  onClick={() => setMaterialIdx(idx)}
                  className={`flex-1 py-3 px-3 text-[11px] font-bold rounded-xl border-2 transition-all duration-200 ${
                    materialIdx === idx 
                      ? 'bg-theme-bg border-theme-accent text-theme-accent' 
                      : 'bg-white border-theme-border text-theme-text opacity-40 hover:opacity-70 hover:border-theme-accent/30'
                  }`}
                >
                  {m.label.split(' ')[0]}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Footer section - Anchored structural integrity */}
        <div className="mt-auto pt-6 border-t border-theme-border flex flex-col gap-5">
          <div className="flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[9px] text-theme-text opacity-40 font-bold uppercase tracking-widest mb-0.5">Giá Hoàn thiện</span>
              <span className="text-3xl font-black text-theme-text tracking-tighter">
                {currentPrice.toLocaleString()}đ
              </span>
            </div>
            <div className="flex items-center bg-theme-bg rounded-xl p-1 gap-1 border border-theme-border shadow-inner">
                <button 
                    onClick={() => setQuantity(q => Math.max(1, q - 1))}
                    className="w-8 h-8 flex items-center justify-center bg-white rounded-lg text-theme-text opacity-60 hover:opacity-100 transition-all springy shadow-sm border border-theme-border"
                >-</button>
                <span className="w-8 text-center text-sm font-black text-theme-text">{quantity}</span>
                <button 
                    onClick={() => setQuantity(q => q + 1)}
                    className="w-8 h-8 flex items-center justify-center bg-white rounded-lg text-theme-text opacity-60 hover:opacity-100 transition-all springy shadow-sm border border-theme-border"
                >+</button>
            </div>
          </div>

          <button
            onClick={handleAdd}
            disabled={isAdding}
            className={`w-full py-4.5 rounded-xl flex items-center justify-center gap-3 font-black text-[11px] tracking-widest transition-all duration-300 springy shadow-md ${
              isAdding 
                ? 'bg-emerald-600 text-white' 
                : 'bg-theme-accent text-white hover:bg-theme-accent-hover'
            }`}
          >
            {isAdding ? (
              <div className="flex items-center gap-2 check-pop">
                <Check size={18} strokeWidth={3} />
                ĐÃ THÊM
              </div>
            ) : (
              <>
                <ShoppingCart size={18} strokeWidth={2.5} />
                ĐẶT MUA NGAY
                <ArrowRight size={16} strokeWidth={2.5} className="ml-0.5" />
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Trophy, X, PartyPopper, Sparkles } from 'lucide-react';

interface LuckySpinProps {
  onWin: (discount: number) => void;
  onClose: () => void;
}

export const LuckySpin: React.FC<LuckySpinProps> = ({ onWin, onClose }) => {
  const [isSpinning, setIsSpinning] = useState(false);
  const [result, setResult] = useState<number | null>(null);
  const slotRef = useRef<HTMLDivElement>(null);

  const rewards = [0, 5, 10, 15, 20];
  const items = [...rewards, ...rewards, ...rewards, ...rewards];

  const handleSpin = () => {
    if (isSpinning) return;
    setIsSpinning(true);
    setResult(null);

    const winningIdx = Math.floor(Math.random() * rewards.length);
    const winValue = rewards[winningIdx];

    const itemHeight = 90; // Standardized vertical rhythm
    const finalIdx = (items.length - rewards.length) + winningIdx;
    const offset = finalIdx * itemHeight;

    if (slotRef.current) {
      slotRef.current.style.transition = 'none';
      slotRef.current.style.transform = 'translateY(0)';
      slotRef.current.offsetHeight; // force reflow

      slotRef.current.style.transition = 'transform 4.5s cubic-bezier(0.1, 0.9, 0.2, 1)';
      slotRef.current.style.transform = `translateY(-${offset}px)`;
    }

    setTimeout(() => {
      setIsSpinning(false);
      setResult(winValue);
      onWin(winValue);
    }, 4700);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-theme-text/10 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="relative bg-white w-full max-w-sm p-10 rounded-[2.5rem] text-center shadow-2xl overflow-hidden border border-theme-border animate-in zoom-in duration-300">
        <div className="absolute top-0 left-0 w-full h-1.5 bg-theme-accent" />

        <button 
          onClick={onClose}
          className="absolute top-6 right-6 p-2.5 text-theme-text opacity-40 hover:opacity-100 transition-all rounded-xl hover:bg-theme-bg border border-transparent hover:border-theme-border springy"
          aria-label="Đóng"
        >
          <X size={22} />
        </button>

        <div className="inline-flex items-center justify-center w-20 h-20 bg-theme-bg rounded-2xl mb-8 text-theme-accent border border-theme-border shadow-inner">
          <Trophy size={36} strokeWidth={1.5} />
        </div>

        <h2 className="text-3xl font-black mb-3 text-theme-text tracking-tight">Hộp Quà May Mắn</h2>
        <p className="text-theme-text opacity-60 mb-10 font-medium text-[13px] leading-relaxed">Săn mã voucher ưu đãi lên đến 20% <br/> áp dụng trực tiếp cho giỏ hàng.</p>

        <div className="relative mb-10">
          <div className="w-44 h-[90px] mx-auto border border-theme-border rounded-[1.75rem] overflow-hidden bg-theme-bg/40 shadow-inner relative">
            <div ref={slotRef} className="flex flex-col">
              {items.map((val, i) => (
                <div key={i} className={`h-[90px] flex items-center justify-center text-4xl font-black ${val > 0 ? 'text-theme-accent' : 'text-theme-text opacity-10'}`}>
                  {val}%
                </div>
              ))}
            </div>
            {/* Horizontal pointer indicator */}
            <div className="absolute inset-x-0 top-1/2 -translate-y-1/2 flex items-center justify-between px-3 pointer-events-none">
              <div className="w-1.5 h-1.5 bg-theme-accent rounded-full shadow-sm" />
              <div className="w-1.5 h-1.5 bg-theme-accent rounded-full shadow-sm" />
            </div>
          </div>

          <div className="absolute -top-4 -right-1 text-theme-accent/30 animate-pulse"><Sparkles size={20}/></div>
          <div className="absolute -bottom-4 -left-1 text-theme-accent/30 animate-bounce"><PartyPopper size={20}/></div>
        </div>

        <button
          onClick={handleSpin}
          disabled={isSpinning || result !== null}
          className={`w-full py-4.5 rounded-xl font-black text-[11px] uppercase tracking-widest transition-all springy shadow-md ${
            isSpinning || result !== null
              ? 'bg-theme-bg text-theme-text opacity-20 border border-theme-border cursor-not-allowed'
              : 'bg-theme-text text-white hover:bg-black'
          }`}
        >
          {isSpinning ? 'ĐANG XOAY...' : result !== null ? 'HOÀN THÀNH' : 'NHẬN ƯU ĐÃI NGAY'}
        </button>

        {result !== null && (
          <div className="mt-8 p-6 bg-theme-bg/50 rounded-2xl border border-theme-border animate-in fade-in slide-in-from-bottom-2 duration-500">
            {result > 0 ? (
              <>
                <p className="text-theme-accent font-black text-[12px] mb-1.5 tracking-wider uppercase flex items-center justify-center gap-2">
                   <PartyPopper size={16} /> XIN CHÚC MỪNG!
                </p>
                <p className="text-theme-text font-bold text-[13px] opacity-80 leading-relaxed">Voucher giảm giá <span className="text-lg font-black underline decoration-theme-accent/40 decoration-4">{result}%</span> đã được áp dụng.</p>
              </>
            ) : (
              <>
                <p className="text-theme-text opacity-40 font-black text-[11px] uppercase tracking-widest">HẸN LẦN SAU NHÉ!</p>
                <p className="text-theme-text opacity-30 text-[11px] font-bold mt-1">Chúc bạn một ngày làm việc hiệu quả! 🍀</p>
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

