            <div className="flex gap-10">
              {['Bảo mật', 'Điều khoản', 'Liên hệ'].map(item => (
                <a key={item} href="#" className="text-[10px] font-bold text-theme-text opacity-30 hover:opacity-60 transition-colors uppercase tracking-widest">{item}</a>
              ))}
            </div>
          </div>
        </div>
      </footer>

      {/* Cart Drawer */}
      {isCartOpen && (
        <div className="fixed inset-0 z-50 flex justify-end">
          <div className="absolute inset-0 bg-theme-text/10 backdrop-blur-sm animate-in fade-in" onClick={() => setIsCartOpen(false)} />
          <div className="relative w-full max-w-lg bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
            <div className="p-10 border-b border-theme-border flex items-center justify-between">
              <div className="flex items-center gap-5">
                <div className="p-3.5 bg-theme-accent-light rounded-xl text-theme-accent border border-theme-accent/20"><ShoppingBag size={24} /></div>
                <h2 className="text-3xl font-black text-theme-text tracking-tighter">Giỏ Hàng</h2>
              </div>
              <button onClick={() => setIsCartOpen(false)} className="p-3.5 bg-theme-bg text-theme-text opacity-40 hover:opacity-100 hover:text-rose-500 rounded-xl border border-theme-border springy"><X size={24} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-10 space-y-10">
              {cart.length === 0 ? (
                <div className="text-center py-40 flex flex-col items-center">
                  <div className="w-24 h-24 bg-theme-bg rounded-[2rem] flex items-center justify-center text-theme-text opacity-10 mb-10 border border-theme-border"><ShoppingBag size={48} /></div>
                  <p className="text-theme-text opacity-40 font-bold text-lg mb-10">Giỏ hàng của bạn đang trống</p>
                  <button onClick={() => setIsCartOpen(false)} className="text-theme-accent font-black text-[11px] uppercase tracking-widest border-b-2 border-theme-accent/30 hover:border-theme-accent transition-all pb-2">KHÁM PHÁ NGAY</button>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.id} className="group bg-theme-bg/20 p-8 rounded-3xl border border-theme-border relative hover:bg-white hover:border-theme-accent/40 transition-all shadow-sm">
                    <button onClick={() => removeFromCart(item.id)} className="absolute top-6 right-6 p-2 opacity-0 group-hover:opacity-100 text-theme-text opacity-30 hover:text-rose-500 transition-all springy"><Trash2 size={20} /></button>
                    <div className="flex flex-col gap-4">
                      <h4 className="font-black text-xl text-theme-text pr-12 leading-tight">{item.name}</h4>
                      <div className="flex flex-wrap gap-2.5 text-[10px] text-theme-text opacity-60 font-bold uppercase tracking-widest">
                        <span className="bg-white px-4 py-1.5 rounded-lg border border-theme-border">{item.size}</span>
                        <span className="bg-white px-4 py-1.5 rounded-lg border border-theme-border">{item.material}</span>
                        <span className="bg-white px-4 py-1.5 rounded-lg border border-theme-border">x{item.quantity}</span>
                      </div>
                      <div className="text-2xl font-black text-theme-text mt-2">{item.price.toLocaleString()}đ</div>
                    </div>
                  </div>
                ))
              )}
            </div>

            <div className="p-10 border-t border-theme-border bg-theme-bg/30">
              <div className="space-y-5 mb-10">
                <div className="flex justify-between text-[13px] font-bold text-theme-text opacity-40 uppercase tracking-widest"><span>Tạm Tính</span><span className="text-theme-text opacity-80">{subtotal.toLocaleString()}đ</span></div>
                {discount > 0 && <div className="flex justify-between text-[13px] font-bold text-theme-accent uppercase tracking-widest"><span>Voucher Daylight ({discount}%)</span><span>-{ (subtotal * discount / 100).toLocaleString() }đ</span></div>}
                <div className="flex justify-between text-4xl font-black pt-10 border-t border-theme-accent/20 text-theme-text tracking-tighter"><span>TỔNG CỘNG</span><span>{total.toLocaleString()}đ</span></div>
              </div>
              <button onClick={handleOrder} className="w-full py-6 bg-theme-accent text-white font-black rounded-2xl hover:bg-theme-accent-hover transition-all shadow-lg shadow-theme-accent/20 text-[13px] tracking-widest springy uppercase">Đặt hàng qua Zalo</button>
            </div>
          </div>
        </div>
      )}

      {/* Wishlist Drawer */}
      {isWishlistOpen && (
        <div className="fixed inset-0 z-50 flex justify-end">
          <div className="absolute inset-0 bg-theme-text/10 backdrop-blur-sm animate-in fade-in" onClick={() => setIsWishlistOpen(false)} />
          <div className="relative w-full max-w-lg bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-400">
            <div className="p-10 border-b border-theme-border flex items-center justify-between">
              <div className="flex items-center gap-5">
                <div className="p-3.5 bg-rose-50 rounded-xl text-rose-500 border border-rose-100"><Heart size={24} fill="currentColor" /></div>
                <h2 className="text-3xl font-black text-theme-text tracking-tighter">Yêu Thích</h2>
              </div>
              <button onClick={() => setIsWishlistOpen(false)} className="p-3.5 bg-theme-bg text-theme-text opacity-40 hover:opacity-100 hover:text-rose-500 rounded-xl border border-theme-border springy"><X size={24} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-10 space-y-10">
              {wishlist.length === 0 ? (
                <div className="text-center py-40">
                  <div className="w-24 h-24 bg-theme-bg rounded-[2rem] flex items-center justify-center text-theme-text opacity-10 mx-auto mb-10 border border-theme-border"><Heart size={48} /></div>
                  <p className="text-theme-text opacity-40 font-bold text-lg">Bạn chưa yêu thích mẫu nào</p>
                </div>
              ) : (
                wishlist.map(product => (
                  <div key={product.id} className="group bg-theme-bg/20 p-8 rounded-3xl border border-theme-border flex gap-8 hover:bg-white hover:border-theme-accent/40 transition-all shadow-sm">
                    <div className="w-28 h-28 rounded-2xl overflow-hidden shrink-0 bg-white border border-theme-border shadow-inner"><img src={product.image} alt={product.name} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" /></div>
                    <div className="flex-1 flex flex-col justify-between py-1">
                      <div>
                        <h4 className="font-black text-xl text-theme-text leading-tight mb-2 pr-6">{product.name}</h4>
                        <p className="text-theme-accent font-bold text-sm tracking-tight">Giá từ {product.basePrice.toLocaleString()}đ</p>
                      </div>
                      <div className="flex items-center gap-8 mt-6">
                        <button onClick={() => { setIsWishlistOpen(false); document.getElementById(`product-${product.id}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' }); }} className="text-[10px] uppercase font-black tracking-widest text-theme-accent border-b-2 border-theme-accent/20 hover:border-theme-accent transition-all pb-1 flex items-center gap-2">CẤU HÌNH <ChevronRight size={14} /></button>
                        <button onClick={() => toggleWishlist(product)} className="text-[10px] uppercase font-black tracking-widest text-theme-text opacity-30 hover:text-rose-500 transition-colors springy">XÓA</button>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>

            <div className="p-10 border-t border-theme-border bg-theme-bg/20">
              <button onClick={() => setIsWishlistOpen(false)} className="w-full py-5 bg-white border border-theme-border text-theme-text rounded-xl font-bold text-[11px] uppercase tracking-widest shadow-sm hover:bg-theme-bg transition-all springy">TIẾP TỤC XEM MẪU</button>
            </div>
          </div>
        </div>
      )}

      {/* Reward Button */}
      {!hasSpun && !showLucky && (
        <button onClick={() => setShowLucky(true)} className="fixed bottom-10 left-10 z-40 w-16 h-16 bg-white rounded-[1.75rem] flex items-center justify-center text-theme-accent shadow-2xl border border-theme-border hover:scale-110 active:scale-95 transition-all duration-300 group overflow-hidden">
          <div className="absolute inset-0 bg-theme-accent-light transform -translate-y-full group-hover:translate-y-0 transition-transform duration-500" />
          <Gift size={28} strokeWidth={1.5} className="relative z-10 group-hover:rotate-12 transition-transform duration-300" />
          <div className="absolute -top-1 -right-1 w-5 h-5 bg-theme-accent rounded-full border-4 border-white animate-pulse" />
        </button>
      )}

      {showLucky && (
        <LuckySpin 
          onWin={(val) => { setDiscount(val); setHasSpun(true); }} 
          onClose={() => setShowLucky(false)} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Product, CartItem } from '../types';
import { SIZES, MATERIALS } from '../constants';
import { ShoppingCart, Check, Heart, ArrowRight } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  isWishlisted: boolean;
  onAddToCart: (item: CartItem) => void;
  onToggleWishlist: (product: Product) => void;
}

export const ProductCard: React.FC<ProductCardProps> = ({ 
  product, 
  isWishlisted, 
  onAddToCart, 
  onToggleWishlist 
}) => {
  const [sizeIdx, setSizeIdx] = useState(0);
  const [materialIdx, setMaterialIdx] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [isAdding, setIsAdding] = useState(false);

  const currentPrice = useMemo(() => {
    return Math.round(
      product.basePrice * 
      SIZES[sizeIdx].multiplier * 
      MATERIALS[materialIdx].multiplier * 
      quantity
    );
  }, [product.basePrice, sizeIdx, materialIdx, quantity]);

  const handleAdd = () => {
    setIsAdding(true);
    onAddToCart({
      id: `${product.id}-${Date.now()}`,
      productId: product.id,
      name: product.name,
      size: SIZES[sizeIdx].label,
      sizeMultiplier: SIZES[sizeIdx].multiplier,
      material: MATERIALS[materialIdx].label,
      materialMultiplier: MATERIALS[materialIdx].multiplier,
      quantity,
      price: currentPrice
    });
    setTimeout(() => setIsAdding(false), 1200);
  };

  return (
    <div className="group relative bg-white rounded-3xl overflow-hidden card-shadow flex flex-col h-full" id={`product-${product.id}`}>
      {/* Favorite Button */}
      <button 
        onClick={() => onToggleWishlist(product)}
        className={`absolute top-4 right-4 z-10 p-2.5 rounded-full bg-white/95 backdrop-blur-md shadow-sm border border-theme-border transition-all duration-200 springy ${
          isWishlisted ? 'text-rose-500' : 'text-theme-text opacity-20 hover:opacity-100 hover:text-rose-500'
        }`}
        aria-label="Yêu thích"
      >
        <Heart size={18} fill={isWishlisted ? "currentColor" : "none"} strokeWidth={isWishlisted ? 0 : 2} />
      </button>

      {/* Product Image Container */}
      <div className="relative aspect-[4/3] bg-theme-bg overflow-hidden cursor-pointer">
        <img 
          src={product.image} 
          alt={product.name}
          className="w-full h-full object-cover transition-transform duration-700 ease-out group-hover:scale-110"
        />
        {product.badge && (
          <div className="absolute top-4 left-4 px-3 py-1 bg-theme-accent text-white text-[9px] font-black tracking-widest rounded-lg uppercase shadow-md shadow-theme-accent/20">
            {product.badge}
          </div>
        )}
      </div>

      <div className="p-7 flex-1 flex flex-col">
        <h3 className="text-2xl font-black mb-5 text-theme-text tracking-tight leading-snug group-hover:text-theme-accent transition-colors duration-300">
          {product.name}
        </h3>

        <div className="space-y-5 mb-8">
          {/* Size Selector */}
          <div>
            <label className="block text-[10px] font-bold text-theme-text opacity-40 uppercase tracking-widest mb-2.5 ml-0.5">Kích thước</label>
            <div className="flex gap-1.5 p-1.5 bg-theme-bg border border-theme-border rounded-2xl shadow-inner">
              {SIZES.map((s, idx) => (
                <button
                  key={s.label}
                  onClick={() => setSizeIdx(idx)}
                  className={`flex-1 py-2 text-[11px] font-bold rounded-xl transition-all duration-200 ${
                    sizeIdx === idx 
                      ? 'bg-white text-theme-accent shadow-md border border-theme-accent/20' 
                      : 'text-theme-text opacity-40 hover:opacity-100 hover:bg-theme-accent-light'
                  }`}
                >
                  {s.label}
                </button>
              ))}
            </div>
          </div>

          {/* Material Selector */}
          <div>
            <label className="block text-[10px] font-bold text-theme-text opacity-40 uppercase tracking-widest mb-2.5 ml-0.5">Vật liệu in</label>
            <div className="flex gap-3">
              {MATERIALS.map((m, idx) => (
                <button
                  key={m.label}
                  onClick={() => setMaterialIdx(idx)}
                  className={`flex-1 py-3 px-3 text-[11px] font-bold rounded-2xl border-2 transition-all duration-200 ${
                    materialIdx === idx 
                      ? 'bg-theme-accent-light border-theme-accent text-theme-accent shadow-sm' 
                      : 'bg-white border-theme-border text-theme-text opacity-40 hover:opacity-100 hover:border-theme-accent/40'
                  }`}
                >
                  {m.label.split(' ')[0]}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Footer section */}
        <div className="mt-auto pt-6 border-t border-theme-border flex flex-col gap-5">
          <div className="flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[9px] text-theme-text opacity-40 font-bold uppercase tracking-widest mb-0.5">Giá Hoàn thiện</span>
              <span className="text-3xl font-black text-theme-text tracking-tighter">
                {currentPrice.toLocaleString()}đ
              </span>
            </div>
            <div className="flex items-center bg-theme-bg rounded-xl p-1 gap-1 border border-theme-border shadow-inner">
                <button 
                    onClick={() => setQuantity(q => Math.max(1, q - 1))}
                    className="w-8 h-8 flex items-center justify-center bg-white rounded-lg text-theme-text opacity-60 hover:opacity-100 hover:text-theme-accent transition-all springy shadow-sm border border-theme-border"
                >-</button>
                <span className="w-8 text-center text-sm font-black text-theme-text">{quantity}</span>
                <button 
                    onClick={() => setQuantity(q => q + 1)}
                    className="w-8 h-8 flex items-center justify-center bg-white rounded-lg text-theme-text opacity-60 hover:opacity-100 hover:text-theme-accent transition-all springy shadow-sm border border-theme-border"
                >+</button>
            </div>
          </div>

          <button
            onClick={handleAdd}
            disabled={isAdding}
            className={`w-full py-4.5 rounded-2xl flex items-center justify-center gap-3 font-black text-[11px] tracking-widest transition-all duration-300 springy shadow-lg ${
              isAdding 
                ? 'bg-emerald-600 text-white shadow-none' 
                : 'bg-theme-accent text-white hover:bg-theme-accent-hover shadow-theme-accent/20'
            }`}
          >
            {isAdding ? (
              <div className="flex items-center gap-2 check-pop">
                <Check size={18} strokeWidth={3} />
                ĐÃ THÊM
              </div>
            ) : (
              <>
                <ShoppingCart size={18} strokeWidth={2.5} />
                ĐẶT MUA NGAY
                <ArrowRight size={16} strokeWidth={2.5} className="ml-0.5" />
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Trophy, X, PartyPopper, Sparkles } from 'lucide-react';

interface LuckySpinProps {
  onWin: (discount: number) => void;
  onClose: () => void;
}

export const LuckySpin: React.FC<LuckySpinProps> = ({ onWin, onClose }) => {
  const [isSpinning, setIsSpinning] = useState(false);
  const [result, setResult] = useState<number | null>(null);
  const slotRef = useRef<HTMLDivElement>(null);

  const rewards = [0, 5, 10, 15, 20];
  const items = [...rewards, ...rewards, ...rewards, ...rewards];

  const handleSpin = () => {
    if (isSpinning) return;
    setIsSpinning(true);
    setResult(null);

    const winningIdx = Math.floor(Math.random() * rewards.length);
    const winValue = rewards[winningIdx];

    const itemHeight = 90;
    const finalIdx = (items.length - rewards.length) + winningIdx;
    const offset = finalIdx * itemHeight;

    if (slotRef.current) {
      slotRef.current.style.transition = 'none';
      slotRef.current.style.transform = 'translateY(0)';
      slotRef.current.offsetHeight; // force reflow

      slotRef.current.style.transition = 'transform 4.5s cubic-bezier(0.1, 0.9, 0.2, 1)';
      slotRef.current.style.transform = `translateY(-${offset}px)`;
    }

    setTimeout(() => {
      setIsSpinning(false);
      setResult(winValue);
      onWin(winValue);
    }, 4700);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-theme-text/20 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="relative bg-white w-full max-w-sm p-10 rounded-[3rem] text-center shadow-2xl overflow-hidden border border-theme-border animate-in zoom-in duration-300">
        <div className="absolute top-0 left-0 w-full h-1.5 bg-theme-accent shadow-sm" />

        <button 
          onClick={onClose}
          className="absolute top-6 right-6 p-2.5 text-theme-text opacity-40 hover:opacity-100 transition-all rounded-xl hover:bg-theme-bg border border-transparent hover:border-theme-border springy"
          aria-label="Đóng"
        >
          <X size={22} />
        </button>

        <div className="inline-flex items-center justify-center w-20 h-20 bg-theme-accent-light rounded-3xl mb-8 text-theme-accent border border-theme-accent/20 shadow-inner">
          <Trophy size={36} strokeWidth={1.5} />
        </div>

        <h2 className="text-3xl font-black mb-3 text-theme-text tracking-tight">Vòng Quay Daylight</h2>
        <p className="text-theme-text opacity-60 mb-10 font-medium text-[13px] leading-relaxed">Khám phá mã voucher ưu đãi lên đến 20% <br/> áp dụng trực tiếp cho giỏ hàng hôm nay.</p>

        <div className="relative mb-10">
          <div className="w-44 h-[90px] mx-auto border border-theme-border rounded-[2rem] overflow-hidden bg-theme-bg/60 shadow-inner relative">
            <div ref={slotRef} className="flex flex-col">
              {items.map((val, i) => (
                <div key={i} className={`h-[90px] flex items-center justify-center text-4xl font-black ${val > 0 ? 'text-theme-accent' : 'text-theme-text opacity-10'}`}>
                  {val}%
                </div>
              ))}
            </div>
            {/* Horizontal pointer indicator */}
            <div className="absolute inset-x-0 top-1/2 -translate-y-1/2 flex items-center justify-between px-3 pointer-events-none">
              <div className="w-2 h-2 bg-theme-accent rounded-full shadow-sm" />
              <div className="w-2 h-2 bg-theme-accent rounded-full shadow-sm" />
            </div>
          </div>

          <div className="absolute -top-4 -right-1 text-theme-accent/40 animate-pulse"><Sparkles size={20}/></div>
          <div className="absolute -bottom-4 -left-1 text-theme-accent/40 animate-bounce"><PartyPopper size={20}/></div>
        </div>

        <button
          onClick={handleSpin}
          disabled={isSpinning || result !== null}
          className={`w-full py-4.5 rounded-2xl font-black text-[11px] uppercase tracking-widest transition-all springy shadow-lg ${
            isSpinning || result !== null
              ? 'bg-theme-bg text-theme-text opacity-20 border border-theme-border cursor-not-allowed'
              : 'bg-theme-accent text-white hover:bg-theme-accent-hover shadow-theme-accent/20'
          }`}
        >
          {isSpinning ? 'ĐANG XOAY...' : result !== null ? 'HOÀN THÀNH' : 'THỬ VẬN MAY NGAY'}
        </button>

        {result !== null && (
          <div className="mt-8 p-6 bg-theme-accent-light rounded-[2rem] border border-theme-accent/20 animate-in fade-in slide-in-from-bottom-2 duration-500">
            {result > 0 ? (
              <>
                <p className="text-theme-accent font-black text-[12px] mb-1.5 tracking-wider uppercase flex items-center justify-center gap-2">
                   <PartyPopper size={16} /> TUYỆT VỜI!
                </p>
                <p className="text-theme-text font-bold text-[13px] opacity-80 leading-relaxed">Bạn nhận được voucher <span className="text-lg font-black text-theme-accent underline decoration-theme-accent/40 decoration-4">{result}%</span> cho đơn hàng này.</p>
              </>
            ) : (
              <>
                <p className="text-theme-text opacity-40 font-black text-[11px] uppercase tracking-widest">HẸN LẦN SAU NHÉ!</p>
                <p className="text-theme-text opacity-30 text-[11px] font-bold mt-1">Chúc bạn một ngày tràn đầy năng lượng! 🍀</p>
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
};
